export const GENERATED_QUESTIONS: SeedQuestion[] = [
  {"section":"READING","topic":"craft-structure","subtopic":"Distinguish Between Fact and Opinion","difficulty":1,"stem":"Read the passage:\n\n\"The public library opened in 1962 and now holds more than 80,000 books. In my view, it is the most beautiful building in the entire town. It also offers free internet access to all visitors.\"\n\nWhich sentence from the passage states an opinion rather than a fact?","options":["The public library opened in 1962.","It also offers free internet access to all visitors.","In my view, it is the most beautiful building in the entire town.","The library now holds more than 80,000 books."],"correct":[2],"explanation":"The phrase \"In my view\" and the judgment \"most beautiful\" express a personal evaluation that cannot be verified, marking it as opinion; the other statements can be checked against records."},
  {"section":"READING","topic":"craft-structure","subtopic":"Distinguish Between Fact and Opinion","difficulty":2,"stem":"Read the passage:\n\n\"Aloe vera plants store water in their thick leaves, which is why they survive in dry climates. Many gardeners believe aloe is the easiest houseplant anyone could ever own. The gel inside the leaves is commonly used in skin lotions.\"\n\nWhich statement from the passage is best classified as an opinion?","options":["Aloe vera plants store water in their thick leaves.","Aloe survives in dry climates.","The gel inside the leaves is used in skin lotions.","Aloe is the easiest houseplant anyone could ever own."],"correct":[3],"explanation":"\"The easiest houseplant anyone could ever own\" is a subjective judgment introduced by \"Many gardeners believe,\" signaling a belief rather than a verifiable fact."},
  {"section":"READING","topic":"craft-structure","subtopic":"Distinguish Between Fact and Opinion","difficulty":2,"stem":"Read the passage:\n\n\"The new electric buses cost the city $4 million. They produce zero tailpipe emissions while running. Honestly, switching the whole fleet to electric was the smartest decision the council has made in decades.\"\n\nWhich sentence expresses an opinion?","options":["Both the first and second sentences.","Switching the whole fleet to electric was the smartest decision the council has made in decades.","The new electric buses cost the city $4 million.","They produce zero tailpipe emissions while running."],"correct":[1],"explanation":"\"Honestly\" and the superlative \"smartest decision...in decades\" signal a personal evaluation that cannot be proven, while the cost and emissions claims are measurable facts."},
  {"section":"READING","topic":"craft-structure","subtopic":"Identify Biases and Stereotypes","difficulty":2,"stem":"Read the passage:\n\n\"When we hired the new accountant, I was surprised. Women are usually too emotional to handle the pressure of managing a company's finances, yet she has kept our books flawless for two years.\"\n\nWhich element of the passage reflects a stereotype?","options":["The assumption that women are too emotional to manage finances.","The writer's surprise at the hiring decision.","The fact that the books have been flawless for two years.","The claim that the accountant was hired recently."],"correct":[0],"explanation":"Stating that \"women are usually too emotional\" applies a broad, unfair generalization to an entire group, which is the defining feature of a stereotype."},
  {"section":"READING","topic":"craft-structure","subtopic":"Identify Biases and Stereotypes","difficulty":2,"stem":"Read the passage:\n\n\"This review of the city budget is completely one-sided. The author lists every program he personally dislikes as 'wasteful' while praising every project in his own neighborhood, ignoring any data that might contradict him.\"\n\nThe passage suggests the budget review is flawed mainly because the author shows what?","options":["Bias in favor of his own interests","A lack of writing experience","A misunderstanding of math","Too much reliance on statistics"],"correct":[0],"explanation":"Praising projects in his own neighborhood while dismissing others he dislikes and ignoring contradicting data reveals a personal bias, a one-sided slant favoring the author's interests."},
  {"section":"READING","topic":"craft-structure","subtopic":"Identify Biases and Stereotypes","difficulty":3,"stem":"Read the passage:\n\n\"The travel guide claims that every tourist will 'instantly fall in love' with the resort, calls the competing hotels 'dreary failures,' and never mentions a single drawback of the property it describes. The guide was, it turns out, paid for by the resort itself.\"\n\nWhich detail most clearly signals that the guide is biased?","options":["It presents only positive points and was funded by the resort.","It was written for tourists.","It uses the phrase 'fall in love.'","It mentions competing hotels by category."],"correct":[0],"explanation":"Presenting only favorable claims, omitting any drawbacks, and being paid for by the resort it praises all show the guide is slanted toward one side rather than balanced."},
  {"section":"READING","topic":"craft-structure","subtopic":"Interpret the Meaning of Words and Phrases Using Context","difficulty":1,"stem":"Read the sentence:\n\n\"After the long hike, the water in our bottles was tepid, neither refreshingly cold nor hot enough for tea.\"\n\nAs used in the sentence, the word \"tepid\" most nearly means:","options":["Lukewarm","Frozen solid","Boiling","Carbonated"],"correct":[0],"explanation":"The phrase \"neither refreshingly cold nor hot enough\" places the water between the two extremes, so \"tepid\" means lukewarm."},
  {"section":"READING","topic":"craft-structure","subtopic":"Interpret the Meaning of Words and Phrases Using Context","difficulty":2,"stem":"Read the sentence:\n\n\"The committee's decision was not final but provisional, subject to change once the full survey results arrived.\"\n\nAs used in the sentence, \"provisional\" most nearly means:","options":["Temporary and conditional","Popular and approved","Secret and unofficial","Permanent and binding"],"correct":[0],"explanation":"The contrast with \"not final\" and the clause \"subject to change once the results arrived\" show that \"provisional\" means temporary and conditional."},
  {"section":"READING","topic":"craft-structure","subtopic":"Interpret the Meaning of Words and Phrases Using Context","difficulty":2,"stem":"Read the sentence:\n\n\"Although the politician promised reform, her critics called the speech mere rhetoric, full of grand phrases but empty of any concrete plan.\"\n\nAs used in the sentence, \"rhetoric\" most nearly means:","options":["Friendly casual conversation","Honest scientific evidence","Showy language lacking real substance","Detailed legal contracts"],"correct":[2],"explanation":"The description \"full of grand phrases but empty of any concrete plan\" defines \"rhetoric\" here as impressive-sounding but hollow language."},
  {"section":"READING","topic":"craft-structure","subtopic":"Interpret the Meaning of Words and Phrases Using Context","difficulty":3,"stem":"Read the sentence:\n\n\"The normally reserved coach gave an animated, arm-waving speech that fired up the whole team before the championship game.\"\n\nAs used in the sentence, \"animated\" most nearly means:","options":["Brief and forgettable","Created with cartoon drawings","Quiet and withdrawn","Lively and full of energy"],"correct":[3],"explanation":"The contrast with \"normally reserved\" and the details \"arm-waving\" and \"fired up the whole team\" show that \"animated\" means lively and energetic, not the unrelated cartoon sense of the word."},
  {"section":"READING","topic":"craft-structure","subtopic":"Use Dictionary and Library Entries","difficulty":2,"stem":"Read the dictionary entry:\n\ncurrent (\\u02c8kər-ənt) adjective, noun\n1. adjective. belonging to the present time; happening now\n2. noun. a steady flow of water, air, or electricity in one direction\n3. noun. a general tendency or movement of opinion\n\nIn which sentence is \"current\" used in the sense of definition 2?\n\n\"Swimmers were warned that the strong current near the rocks could pull them out to sea.\"","options":["None of the definitions","Definition 3","Definition 2","Definition 1"],"correct":[2],"explanation":"In the sentence, \"current\" refers to a steady flow of water that could pull swimmers, matching the noun sense in definition 2."},
  {"section":"READING","topic":"craft-structure","subtopic":"Use Dictionary and Library Entries","difficulty":2,"stem":"Read the dictionary entry:\n\ntemper (\\u02c8tem-pər) noun, verb\n1. noun. a person's state of mind or mood\n2. noun. a tendency to become angry easily\n3. verb. to soften or moderate the effect of something\n4. verb. to harden metal by heating and cooling it\n\nWhich definition fits the use of \"temper\" in this sentence?\n\n\"The judge chose to temper the harsh sentence with a chance for early release.\"","options":["Definition 3","Definition 4","Definition 1","Definition 2"],"correct":[0],"explanation":"Here \"temper\" is a verb meaning to soften or moderate the harshness of the sentence, matching definition 3."},
  {"section":"READING","topic":"craft-structure","subtopic":"Use Dictionary and Library Entries","difficulty":2,"stem":"A dictionary page shows the guide words \"marble\" and \"margin\" at the top. Which of the following words would appear on this page?","options":["marvel","march","manner","mark"],"correct":[1],"explanation":"Guide words are the first and last entries on the page, so only a word that falls alphabetically between \"marble\" and \"margin\" belongs. Comparing third letters, \"march\" (mar-c) falls between \"marble\" (mar-b) and \"margin\" (mar-g). \"manner\" comes before \"marble\"; \"mark\" (mar-k) and \"marvel\" both come after \"margin.\""},
  {"section":"READING","topic":"craft-structure","subtopic":"Use Dictionary and Library Entries","difficulty":3,"stem":"A library catalog entry reads:\n\nTitle: Rivers of Stone: A History of Bridges\nAuthor: Patel, Anika\nCall Number: 624.2 PAT\nSubjects: Bridges—Design and construction; Civil engineering\nLocation: Nonfiction, 2nd floor\n\nA student needs another book on the same shelf about building structures. Which piece of information is most useful for locating nearby books on related engineering topics?","options":["The 2nd floor location only","The author's last name","The title of the book","The call number 624.2"],"correct":[3],"explanation":"In a library, the call number groups books by subject on the shelf, so the number 624.2 leads the student to other engineering and construction titles shelved nearby."},
  {"section":"READING","topic":"craft-structure","subtopic":"Evaluate the Author's Purpose in a Given Text","difficulty":1,"stem":"Read the passage:\n\n\"To replace the printer cartridge, first open the front panel by pressing the gray tab. Remove the empty cartridge by lifting it straight up. Slide the new cartridge into the slot until it clicks, then close the panel.\"\n\nWhat is the author's primary purpose in this passage?","options":["To entertain readers with a personal story","To instruct readers on how to complete a task","To describe the history of printing","To persuade readers to buy a new printer"],"correct":[1],"explanation":"The numbered, step-by-step directions for replacing a cartridge show the author's purpose is to instruct the reader how to perform a task."},
  {"section":"READING","topic":"craft-structure","subtopic":"Evaluate the Author's Purpose in a Given Text","difficulty":2,"stem":"Read the passage:\n\n\"Our neighborhood park is falling apart, and we cannot wait any longer. Cracked pathways and broken benches put families at risk every day. Sign the petition today and demand that the city fund repairs before someone is hurt.\"\n\nWhat is the author's primary purpose?","options":["To entertain readers with a funny anecdote","To explain how parks are constructed","To persuade readers to support park repairs","To compare two different parks"],"correct":[2],"explanation":"The urgent tone and the direct call to \"Sign the petition today and demand\" funding show the author's purpose is to persuade readers to take action."},
  {"section":"READING","topic":"craft-structure","subtopic":"Evaluate the Author's Purpose in a Given Text","difficulty":3,"stem":"Read the passage:\n\n\"A honeybee colony functions as a single organism. Worker bees gather nectar, nurse bees feed the young, and the queen lays thousands of eggs each day. Each role is essential, and the loss of any group can threaten the entire hive's survival.\"\n\nThe author's main purpose is to:","options":["Criticize farmers who harm bees","Inform readers about how a bee colony works","Convince readers to start beekeeping","Share a personal memory of a bee sting"],"correct":[1],"explanation":"The passage neutrally explains the roles of different bees and how they keep the hive alive, showing the purpose is to inform the reader about how a colony functions."},
  {"section":"READING","topic":"craft-structure","subtopic":"Recognize Text Structure","difficulty":2,"stem":"Read the passage:\n\n\"Because the factory dumped waste into the river for years, the fish population collapsed. As a result, local fishers lost their income, and several family businesses were forced to close.\"\n\nWhich text structure does this passage use?","options":["Chronological sequence","Spatial description","Cause and effect","Compare and contrast"],"correct":[2],"explanation":"The signal words \"Because\" and \"As a result\" link an action to its consequences, marking a cause-and-effect structure."},
  {"section":"READING","topic":"craft-structure","subtopic":"Recognize Text Structure","difficulty":2,"stem":"Read the passage:\n\n\"Both online courses and traditional classes can lead to a degree. However, online courses offer flexible scheduling, while traditional classes provide face-to-face interaction with instructors and classmates.\"\n\nWhich text structure best describes this passage?","options":["Compare and contrast","Cause and effect","Chronological order","Problem and solution"],"correct":[0],"explanation":"The passage points out a similarity (\"Both...can lead to a degree\") and differences signaled by \"However\" and \"while,\" which is the compare-and-contrast structure."},
  {"section":"READING","topic":"craft-structure","subtopic":"Recognize Text Structure","difficulty":3,"stem":"Read the passage:\n\n\"Traffic on Main Street has become dangerous during school hours. To address this, the town could add a crosswalk, lower the speed limit, and station a crossing guard near the entrance. These steps would protect students walking to class.\"\n\nWhich text structure organizes this passage?","options":["Description","Chronological sequence","Problem and solution","Compare and contrast"],"correct":[2],"explanation":"The passage first identifies a problem (dangerous traffic) and then proposes specific remedies (\"To address this...\"), which is the problem-and-solution structure."},
  {"section":"READING","topic":"craft-structure","subtopic":"Analyze Types of Writing","difficulty":2,"stem":"Read the passage:\n\n\"The old lighthouse stood at the edge of the cliff, its white paint peeling and its windows clouded with salt. Waves crashed against the rocks below, sending cold spray into the gray morning air.\"\n\nWhich type of writing best describes this passage?","options":["Expository","Persuasive","Technical","Descriptive"],"correct":[3],"explanation":"The passage uses vivid sensory details about the lighthouse's appearance and surroundings to create a picture in the reader's mind, which is descriptive writing."},
  {"section":"READING","topic":"craft-structure","subtopic":"Analyze Types of Writing","difficulty":3,"stem":"Read the passage:\n\n\"Every citizen has a duty to vote in local elections. When we stay home, we hand our power to others and lose the right to complain about the results. Make your voice count—register and show up on election day.\"\n\nWhich type of writing is this passage?","options":["Expository","Narrative","Persuasive","Descriptive"],"correct":[2],"explanation":"The passage argues a position and urges readers to register and vote, using a direct appeal, which marks it as persuasive writing."},
  {"section":"READING","topic":"craft-structure","subtopic":"Evaluate the Author's Point of View or Perspective in a Given Text","difficulty":2,"stem":"Read the passage:\n\n\"As a nurse who has worked night shifts for fifteen years, I know firsthand how exhausting these hours can be. Hospitals should rotate staff more often so that no one is forced to work nights month after month.\"\n\nWhich statement best describes the author's perspective?","options":["The author has no personal experience with hospital work.","The author is an experienced nurse who supports rotating night shifts.","The author believes night shifts should be eliminated entirely.","The author is a patient complaining about care."],"correct":[1],"explanation":"The author identifies as a nurse with fifteen years of night-shift experience and argues that hospitals \"should rotate staff more often,\" revealing an insider perspective favoring rotation."},
  {"section":"READING","topic":"craft-structure","subtopic":"Evaluate the Author's Point of View or Perspective in a Given Text","difficulty":3,"stem":"Read the passage:\n\n\"I used to think homework was a waste of time. Now, after tutoring struggling students, I see how a small amount of practice each night helps ideas truly sink in. I still believe, however, that hours of busywork do more harm than good.\"\n\nWhich statement best captures the author's point of view?","options":["The author supports unlimited amounts of homework.","The author has never thought about homework before.","The author favors a moderate amount of meaningful homework but opposes excessive busywork.","The author opposes all forms of homework."],"correct":[2],"explanation":"The author values \"a small amount of practice each night\" while still rejecting \"hours of busywork,\" showing a balanced view that supports moderate, meaningful homework but opposes excess."},
  {"section":"READING","topic":"integration-knowledge","subtopic":"Use Evidence From the Text to Make Predictions, Inferences, and Draw Conclusions","difficulty":2,"stem":"Maria checked the weather app, then placed her umbrella by the front door and slipped a raincoat over her arm before leaving for the bus stop. She also tucked a paperback into her bag, expecting a long wait under the shelter.\n\nBased on the passage, what can the reader most reasonably infer?","options":["The weather forecast predicted rain.","Maria's bus is always exactly on time.","The bus stop has no shelter from the weather.","Maria dislikes reading paperbacks."],"correct":[0],"explanation":"Maria takes an umbrella and raincoat after checking the weather app, so the forecast most likely predicted rain. The other choices contradict or go beyond the text."},
  {"section":"READING","topic":"integration-knowledge","subtopic":"Use Evidence From the Text to Make Predictions, Inferences, and Draw Conclusions","difficulty":2,"stem":"The community garden's sign-up sheet filled completely within two hours of being posted, and the coordinator received a dozen emails that afternoon asking whether more plots could be added. Last spring, by contrast, half the plots sat empty all season.\n\nWhich prediction is best supported by the passage?","options":["The coordinator will likely consider expanding the number of plots.","The coordinator plans to charge higher fees for each plot.","Gardeners will refuse to share tools with one another.","The garden will be closed next season due to low interest."],"correct":[0],"explanation":"High demand and direct requests for more plots make it most reasonable that the coordinator will consider expanding. The other options are unsupported or contradict the surge in interest."},
  {"section":"READING","topic":"integration-knowledge","subtopic":"Use Evidence From the Text to Make Predictions, Inferences, and Draw Conclusions","difficulty":3,"stem":"Dr. Patel reviewed the lab's quarterly results and frowned. \"Every batch we ran after replacing the old centrifuge has shown cleaner separation,\" she noted, \"yet the contamination reports didn't drop until we also switched cleaning agents in March.\" She circled the March entry twice.\n\nWhat conclusion does the passage best support?","options":["The change in cleaning agents, not the new centrifuge alone, was associated with fewer contamination reports.","Dr. Patel intends to remove the new centrifuge from the lab.","The new centrifuge caused all of the contamination problems.","Contamination reports were unaffected by any of the changes."],"correct":[0],"explanation":"Cleaner separation followed the centrifuge swap, but contamination reports fell only after the cleaning-agent switch in March, which Dr. Patel emphasizes. The other choices misread the timeline."},
  {"section":"READING","topic":"integration-knowledge","subtopic":"Use Evidence From the Text to Make Predictions, Inferences, and Draw Conclusions","difficulty":2,"stem":"When the new manager arrived, she replaced the suggestion box with weekly open meetings, posted the budget on the break-room wall, and began answering staff questions by email within a day. Employees who had once spoken only in whispers started raising concerns aloud.\n\nWhat can the reader most reasonably infer about the manager?","options":["She prefers that employees never ask questions.","She values transparency and open communication.","She is uninterested in the staff's opinions.","She plans to cut the department's budget."],"correct":[1],"explanation":"Posting the budget, holding open meetings, and answering questions promptly all point to a manager who values openness. The remaining options contradict her actions."},
  {"section":"READING","topic":"integration-knowledge","subtopic":"Use Evidence From the Text to Make Predictions, Inferences, and Draw Conclusions","difficulty":3,"stem":"The trail guide wrote: \"By midafternoon the clouds had thickened over the ridge, the temperature had dropped sharply, and the marmots that usually sunned on the rocks were nowhere to be seen. We decided to start back early.\"\n\nWhich inference is best supported by the passage?","options":["The trail was closed by park officials that day.","The hikers expected a storm or worsening weather.","The hikers had reached the highest point of the trail.","The marmots had migrated for the winter."],"correct":[1],"explanation":"Thickening clouds, a sharp temperature drop, and absent animals, followed by an early return, point to anticipated bad weather. The other choices are not indicated by the details."},
  {"section":"READING","topic":"integration-knowledge","subtopic":"Compare and Contrast the Themes Expressed in One or More Texts","difficulty":3,"stem":"Passage 1: The old fisherman returned each dawn with empty nets, yet he rowed out again the next morning without complaint. \"The sea owes me nothing,\" he would say, \"but I owe it my effort.\"\n\nPassage 2: The young inventor's first ten machines failed, but she kept sketching new designs late into the night. \"Each broken gear,\" she wrote, \"teaches the next one how to turn.\"\n\nWhich theme is shared by both passages?","options":["The dangers of relying on modern technology.","Persistence in the face of repeated failure.","The value of accepting defeat and moving on.","The importance of working only in groups."],"correct":[1],"explanation":"Both the fisherman who rows out again and the inventor who keeps sketching embody persistence despite repeated failure. The other options fit neither passage."},
  {"section":"READING","topic":"integration-knowledge","subtopic":"Compare and Contrast the Themes Expressed in One or More Texts","difficulty":2,"stem":"Passage 1: In the village, neighbors gathered every harvest to bring in one another's crops, certain that no single family could survive the season alone.\n\nPassage 2: The mountaineer insisted on climbing solo, trusting only her own judgment and refusing every offer of a guide or partner.\n\nHow do the themes of the two passages differ?","options":["Both passages criticize people who work alone.","Passage 1 warns against trusting neighbors, while Passage 2 praises them.","Both passages emphasize the rewards of teamwork.","Passage 1 emphasizes community interdependence, while Passage 2 emphasizes self-reliance."],"correct":[3],"explanation":"Passage 1 stresses mutual dependence among neighbors; Passage 2 stresses the mountaineer's insistence on going it alone. The other options misstate one or both passages."},
  {"section":"READING","topic":"integration-knowledge","subtopic":"Compare and Contrast the Themes Expressed in One or More Texts","difficulty":3,"stem":"Passage 1: The general's memoir celebrated the conquered city as a trophy, listing its riches and the banners his troops raised over its walls.\n\nPassage 2: A displaced resident's diary described the same day as the morning her family's bakery burned and the streets filled with strangers' boots.\n\nWhich statement best compares the themes of the two passages?","options":["Both passages portray the event as a shared celebration.","Neither passage takes a clear point of view on the event.","Both passages mourn the destruction of the city.","Both describe the same event, but one frames it as triumph and the other as loss."],"correct":[3],"explanation":"The general frames the conquest as triumph while the resident frames it as personal loss, contrasting perspectives on one event. The other choices ignore the opposing viewpoints."},
  {"section":"READING","topic":"integration-knowledge","subtopic":"Compare and Contrast the Themes Expressed in One or More Texts","difficulty":2,"stem":"Passage 1: \"Money spent on books is never wasted,\" the teacher told her students, \"for what you read becomes a part of you that no one can take away.\"\n\nPassage 2: A wealthy merchant boasted that his gold was the only treasure worth keeping, since ideas faded but coins endured in the vault.\n\nWhich theme do the two passages most clearly set in opposition?","options":["The value of knowledge versus the value of material wealth.","The importance of honesty versus the cost of deceit.","The benefits of saving versus the dangers of spending.","The wisdom of youth versus the wisdom of age."],"correct":[0],"explanation":"The teacher prizes knowledge while the merchant prizes material wealth, placing those two values in opposition. The other pairs are not the contrast the passages draw."},
  {"section":"READING","topic":"integration-knowledge","subtopic":"Compare and Contrast the Themes Expressed in One or More Texts","difficulty":3,"stem":"Passage 1: The river poem praised change itself: \"What I love about the current is that it is never the same water twice, and so it never grows stale.\"\n\nPassage 2: The lighthouse poem praised constancy: \"In every storm I am the one fixed light, and sailors trust me because I never move.\"\n\nWhich statement best describes how the themes relate?","options":["Both poems argue that change is always harmful.","Neither poem expresses a clear attitude toward change.","One poem celebrates constant change, while the other celebrates steadfast permanence.","Both poems argue that permanence is always comforting."],"correct":[2],"explanation":"The river poem embraces ceaseless change; the lighthouse poem embraces unchanging permanence, presenting opposite themes. The other options collapse or ignore that contrast."},
  {"section":"READING","topic":"integration-knowledge","subtopic":"Evaluate an Argument","difficulty":3,"stem":"A columnist writes: \"Our town should ban all skateboarding downtown. Last year a single skateboarder collided with a pedestrian, proving that skateboards are simply too dangerous for public streets.\"\n\nWhat is the most significant weakness in the columnist's argument?","options":["The argument relies entirely on expert testimony.","The columnist uses too many statistics to make the point.","The columnist fails to mention the skateboarder's age.","A single incident is too little evidence to support a town-wide ban."],"correct":[3],"explanation":"Generalizing from one collision to a sweeping ban is a hasty generalization, the argument's central flaw. The other options describe features the passage does not contain."},
  {"section":"READING","topic":"integration-knowledge","subtopic":"Evaluate an Argument","difficulty":2,"stem":"An advertisement claims: \"Nine out of ten dentists surveyed recommend BrightSmile toothpaste, so it must be the best toothpaste available.\"\n\nWhich question would most help a reader evaluate the strength of this claim?","options":["Which celebrity appears in the advertisement?","How many dentists were surveyed, and how were they chosen?","How long has the company existed?","What color is the toothpaste tube?"],"correct":[1],"explanation":"The survey's size and selection method determine whether the statistic is meaningful, making that the key evaluative question. The other questions are irrelevant to the claim's validity."},
  {"section":"READING","topic":"integration-knowledge","subtopic":"Evaluate an Argument","difficulty":3,"stem":"\"Every successful entrepreneur I interviewed wakes up before 5 a.m.,\" a writer argues. \"Therefore, waking up before 5 a.m. is what makes people successful in business.\"\n\nWhich flaw best describes the reasoning?","options":["It defines success in a way no one would accept.","It contradicts itself within a single sentence.","It relies on a source with no relevant expertise.","It assumes that because two things occur together, one must cause the other."],"correct":[3],"explanation":"The writer treats a correlation between early rising and success as proof of causation, a classic causal error. The other descriptions do not match the argument."},
  {"section":"READING","topic":"integration-knowledge","subtopic":"Evaluate an Argument","difficulty":2,"stem":"A speaker argues: \"We must either build the new highway or watch our city's economy collapse entirely. There is no other choice.\"\n\nWhich weakness does this argument most clearly display?","options":["It cites too much economic data.","It presents only two options when others may exist.","It quotes an anonymous expert.","It appeals to the audience's sense of humor."],"correct":[1],"explanation":"By framing the issue as only highway-or-collapse, the speaker sets up a false dilemma that ignores other possibilities. The other options describe tactics the passage does not use."},
  {"section":"READING","topic":"integration-knowledge","subtopic":"Evaluate an Argument","difficulty":3,"stem":"An author argues that a new reading program improved test scores, citing that the school adopted the program in September and average scores rose by spring. The author does not mention that the school also hired four additional tutors and extended the school day that same year.\n\nWhich statement best evaluates the argument?","options":["The conclusion is strengthened because the timing is precise.","The argument fails because it includes no dates.","The argument is sound because test scores never change on their own.","The conclusion is weakened because other changes could explain the higher scores."],"correct":[3],"explanation":"Because tutors and a longer school day changed at the same time, the rise in scores cannot be attributed to the reading program alone. The other choices ignore these confounding factors."},
  {"section":"READING","topic":"integration-knowledge","subtopic":"Evaluate an Argument","difficulty":2,"stem":"A blogger writes: \"You shouldn't believe Dr. Lee's research on nutrition. After all, she dresses unprofessionally and has an annoying voice.\"\n\nWhat is the main weakness of this argument?","options":["It carefully defines all of its key terms.","It provides too much detail about the research methods.","It relies on a large body of peer-reviewed studies.","It attacks the researcher's personal traits instead of her evidence."],"correct":[3],"explanation":"Criticizing Dr. Lee's appearance and voice rather than her findings is an ad hominem attack that does not address the research. The other options describe strengths the argument lacks."},
  {"section":"READING","topic":"integration-knowledge","subtopic":"Identify Primary Sources","difficulty":2,"stem":"A student is writing a report about a 1955 labor strike and wants to use a primary source. Which of the following would best serve as a primary source for that event?","options":["An encyclopedia entry about labor movements.","A handwritten letter mailed by a worker during the 1955 strike.","A recent documentary analyzing strikes of the 1950s.","A textbook chapter summarizing labor history written in 2010."],"correct":[1],"explanation":"A letter written by a participant during the strike is firsthand evidence and therefore a primary source. The textbook, encyclopedia, and documentary all interpret events after the fact and are secondary."},
  {"section":"READING","topic":"integration-knowledge","subtopic":"Identify Primary Sources","difficulty":2,"stem":"A researcher studying how a 19th-century scientist conducted an experiment wants a primary source. Which item is the primary source for that purpose?","options":["A magazine article reviewing the scientist's legacy.","A biography of the scientist published last year.","The scientist's original laboratory notebook recording the experiment.","A modern textbook describing the experiment's results."],"correct":[2],"explanation":"The scientist's own notebook is a direct, firsthand record of the experiment, making it the primary source. The biography, article, and textbook are later interpretations."},
  {"section":"READING","topic":"integration-knowledge","subtopic":"Identify Primary Sources","difficulty":3,"stem":"A historian wants to understand how ordinary citizens felt during a particular wartime year. Several sources are available. Which would function as a primary source for that goal?","options":["A diary kept by a citizen during that wartime year.","A high school history textbook's chapter on the war.","An online article ranking the war's most important battles.","A peer-reviewed journal article analyzing public morale, published decades later."],"correct":[0],"explanation":"A diary written by a citizen at the time directly records firsthand feelings, serving as a primary source. The journal article, textbook, and ranking article are secondary analyses written later."},
  {"section":"READING","topic":"integration-knowledge","subtopic":"Identify Primary Sources","difficulty":2,"stem":"A journalism class is studying a famous speech. To analyze the speaker's exact original words, which source is the primary source?","options":["A teacher's lecture notes describing the speech.","A transcript of the speech taken from the speaker's own delivered remarks.","A newspaper editorial praising the speech the following week.","A blog post summarizing the speech's main ideas."],"correct":[1],"explanation":"A transcript of the speaker's actual words is a firsthand record and thus the primary source. The editorial, blog post, and lecture notes all comment on or summarize the speech afterward."},
  {"section":"READING","topic":"integration-knowledge","subtopic":"Identify Primary Sources","difficulty":3,"stem":"A nursing student is researching how a new vaccine was first tested and wants the most direct, firsthand evidence. Which source is primary?","options":["A patient-education pamphlet describing the vaccine.","The original clinical trial report written by the researchers who conducted the study.","A review article that compares several vaccine studies.","A news website's article summarizing the trial for the public."],"correct":[1],"explanation":"The researchers' original clinical trial report is the firsthand account of the study, making it the primary source. The news article, review article, and pamphlet all restate or interpret that work."},
  {"section":"READING","topic":"integration-knowledge","subtopic":"Evaluate and Integrate Data From Multiple Sources Across Various Formats","difficulty":3,"stem":"Text: A clinic tracked average patient wait times after adding a second receptionist in March.\n\nMonthly Average Wait (minutes):\nJanuary: 32\nFebruary: 30\nMarch: 24\nApril: 19\nMay: 18\n\nBased on the text and the table together, which conclusion is best supported?","options":["The second receptionist had no effect on wait times.","Wait times were lowest in January.","Wait times decreased after the second receptionist was added in March.","Wait times rose steadily from January through May."],"correct":[2],"explanation":"The table shows wait times dropping from 24 minutes in March to 18 in May, after the March staffing change described in the text. The other options contradict the data."},
  {"section":"READING","topic":"integration-knowledge","subtopic":"Evaluate and Integrate Data From Multiple Sources Across Various Formats","difficulty":2,"stem":"Text: A library reported the number of e-books and printed books checked out each quarter last year.\n\nCheckouts by Quarter:\nQ1 - Printed: 1,200; E-books: 400\nQ2 - Printed: 1,000; E-books: 600\nQ3 - Printed: 900; E-books: 800\nQ4 - Printed: 850; E-books: 1,050\n\nWhich statement is best supported by combining the text and the table?","options":["E-books were never checked out more than printed books.","Printed checkouts increased every quarter.","E-book checkouts rose each quarter while printed checkouts fell.","Total checkouts dropped to zero by Q4."],"correct":[2],"explanation":"Across the four quarters, e-book checkouts climb from 400 to 1,050 while printed checkouts decline from 1,200 to 850. The other options contradict the figures."},
  {"section":"READING","topic":"integration-knowledge","subtopic":"Evaluate and Integrate Data From Multiple Sources Across Various Formats","difficulty":3,"stem":"Text: A coach recorded each runner's best 5K time and the number of weekly training sessions they attended.\n\nRunner Data:\nAna - Sessions: 5; Best time: 22 min\nBen - Sessions: 4; Best time: 24 min\nCara - Sessions: 2; Best time: 28 min\nDev - Sessions: 1; Best time: 31 min\n\nWhich conclusion is best supported by the text and the table?","options":["Runners who attended more weekly sessions tended to post faster times.","Every runner finished in under 25 minutes.","The number of sessions had no relationship to finishing time.","Attending fewer sessions led to faster times."],"correct":[0],"explanation":"As weekly sessions decrease from Ana (5) to Dev (1), best times grow slower (22 to 31 minutes), showing more sessions are associated with faster times. The other options misread the trend."},
  {"section":"READING","topic":"integration-knowledge","subtopic":"Evaluate and Integrate Data From Multiple Sources Across Various Formats","difficulty":2,"type":"MULTI","stem":"Text: A grocery store posted the price per pound of four fruits this week and noted that any fruit priced above $2.00 per pound is considered a \"premium\" item.\n\nPrice per Pound:\nApples: $1.50\nGrapes: $2.75\nBananas: $0.60\nCherries: $4.20\n\nUsing the text and the table, which fruits qualify as \"premium\" items? (Select all that apply.)","options":["Cherries","Bananas","Grapes","Apples"],"correct":[0,2],"explanation":"The text defines premium as priced above $2.00 per pound; grapes ($2.75) and cherries ($4.20) exceed that, while apples ($1.50) and bananas ($0.60) do not."},
  {"section":"READING","topic":"integration-knowledge","subtopic":"Evaluate and Integrate Data From Multiple Sources Across Various Formats","difficulty":3,"stem":"Text: A city compared the number of reported bicycle accidents before and after installing protected bike lanes on Main Street in 2022.\n\nReported Bicycle Accidents on Main Street:\n2020: 18\n2021: 16\n2022 (lanes installed): 11\n2023: 7\n\nWhich conclusion is best supported by combining the text and the table?","options":["Accidents were highest in 2023.","Reported accidents declined after the protected lanes were installed.","Reported accidents increased after the lanes were installed.","The lanes were installed in 2020."],"correct":[1],"explanation":"After the 2022 installation, reported accidents fell from 11 to 7 in 2023, continuing a downward trend, so the data supports a decline. The other options contradict the table."},
  {"section":"READING","topic":"key-ideas-details","subtopic":"Identify the Topic, Main Idea, and Supporting Details","difficulty":1,"stem":"Read the passage and answer the question.\n\nHoneybees do far more than make honey. As they move from flower to flower gathering nectar, they carry pollen on their bodies, fertilizing the plants they visit. Roughly one-third of the food that people eat depends on this pollination. Without honeybees, many fruits and vegetables would become scarce.\n\nWhat is the main idea of the passage?","options":["Honeybees gather nectar from one flower at a time.","Honey is the most important product that bees create.","Honeybees are valuable because their pollination supports much of the human food supply.","Fruits and vegetables grow best in warm climates."],"correct":[2],"explanation":"The passage states bees fertilize plants and 'one-third of the food people eat depends on this pollination,' making option A the central point. The other choices are minor details or unstated claims."},
  {"section":"READING","topic":"key-ideas-details","subtopic":"Identify the Topic, Main Idea, and Supporting Details","difficulty":2,"stem":"Read the passage and answer the question.\n\nFor decades, people believed that adult brains could not change. Recent research, however, shows that the brain continues to form new connections throughout life, a quality called neuroplasticity. Stroke patients, for example, can sometimes retrain undamaged regions to take over lost functions. This discovery has transformed how doctors approach rehabilitation.\n\nWhich sentence best states the topic of the passage?","options":["The passage is about how strokes damage the brain permanently.","The passage is about why doctors disagree on rehabilitation methods.","The passage is about the history of medical research in general.","The passage is about the brain's lifelong ability to change, known as neuroplasticity."],"correct":[3],"explanation":"The passage centers on neuroplasticity, the brain's ability to keep forming connections; the stroke example supports this. B contradicts the text, and C and D are not the focus."},
  {"section":"READING","topic":"key-ideas-details","subtopic":"Identify the Topic, Main Idea, and Supporting Details","difficulty":2,"stem":"Read the passage and answer the question.\n\nThe Great Pacific Garbage Patch is not a solid island of trash, as many imagine. Instead, it is a vast area where tiny pieces of broken-down plastic float just below the surface. Because the particles are so small and spread out, the patch is difficult to see and even harder to clean up.\n\nWhich detail from the passage supports the idea that the patch is hard to clean up?","options":["Many people imagine it as a solid island.","The patch is located in the Pacific Ocean.","The plastic floats below the surface of the water.","The plastic particles are tiny and spread out across a vast area."],"correct":[3],"explanation":"The passage says the particles are 'so small and spread out' that the patch is 'harder to clean up,' directly supporting that claim. The other options are details that do not explain the cleanup difficulty."},
  {"section":"READING","topic":"key-ideas-details","subtopic":"Identify the Topic, Main Idea, and Supporting Details","difficulty":3,"stem":"Read the passage and answer the question.\n\nMany shoppers assume that products labeled 'natural' are healthier than other options. In truth, the word 'natural' has no strict legal definition on food packaging, so manufacturers may apply it loosely. A cereal marked 'natural' can still contain large amounts of added sugar. Buyers who want reliable information should read the ingredient list rather than trust marketing terms.\n\nWhat is the author's main point?","options":["Cereal is one of the unhealthiest foods on the market.","Most manufacturers intentionally deceive their customers.","The label 'natural' is not a reliable guide to a food's healthfulness.","Added sugar is the only ingredient shoppers should avoid."],"correct":[2],"explanation":"The author argues that 'natural' lacks a strict definition and advises reading the ingredient list instead, so A captures the main point. B, C, and D overstate or distort details not claimed in the passage."},
  {"section":"READING","topic":"key-ideas-details","subtopic":"Summarize a Multi-Paragraph Text","difficulty":2,"stem":"Read the passage and answer the question.\n\nVolunteering benefits more than the people who receive help. Studies show that those who volunteer regularly report lower levels of stress and a stronger sense of purpose. Some research even links volunteering to better physical health and longer life.\n\nAt the same time, communities gain skilled, motivated workers at no cost. Schools, hospitals, and food banks often rely on volunteers to provide services they could not otherwise afford.\n\nWhich choice best summarizes the passage?","options":["Hospitals and schools cannot function without volunteer labor.","Volunteering helps the volunteers' own well-being while also providing valuable unpaid labor to communities.","Volunteering is the most effective way to reduce stress in modern life.","Volunteers tend to live longer than people who do not volunteer."],"correct":[1],"explanation":"A combines both paragraphs: personal benefits to volunteers and benefits to communities. The other options each capture only one narrow detail or overstate it."},
  {"section":"READING","topic":"key-ideas-details","subtopic":"Summarize a Multi-Paragraph Text","difficulty":2,"stem":"Read the passage and answer the question.\n\nThe printing press, invented in the 1400s, made books far cheaper to produce. Before its invention, scribes copied texts by hand, a slow process that kept books rare and expensive.\n\nAs printed books spread, literacy rates climbed and new ideas traveled quickly across Europe. Historians often credit the press with helping to spark major social and religious movements.\n\nWhich statement best summarizes the passage?","options":["Scribes refused to copy texts once the printing press was invented.","Books were rare in the 1400s because few people could read.","The printing press was the single cause of every European revolution.","By making books cheap and widespread, the printing press boosted literacy and the spread of ideas."],"correct":[3],"explanation":"The summary must join both paragraphs: cheaper books led to higher literacy and faster spread of ideas. B and C overstate the text, and D reverses the cause-and-effect the passage describes."},
  {"section":"READING","topic":"key-ideas-details","subtopic":"Summarize a Multi-Paragraph Text","difficulty":3,"stem":"Read the passage and answer the question.\n\nElectric vehicles produce no tailpipe emissions, which can improve air quality in crowded cities. For this reason, many governments now offer rebates to encourage their purchase.\n\nHowever, the electricity that powers these cars must come from somewhere. In regions that burn coal to generate power, the overall environmental benefit of an electric vehicle shrinks considerably.\n\nWhich choice best summarizes the passage?","options":["Electric vehicles are always better for the environment than gasoline cars.","Electric vehicles reduce local emissions, but their full environmental benefit depends on how the electricity is generated.","Coal power plants are the main source of air pollution in cities.","Governments should stop offering rebates for electric vehicles."],"correct":[1],"explanation":"The two paragraphs present a benefit and a qualification, which A captures. B ignores the second paragraph, and C and D are conclusions the passage does not make."},
  {"section":"READING","topic":"key-ideas-details","subtopic":"Infer Logical Conclusions From a Text","difficulty":2,"stem":"Read the passage and answer the question.\n\nWhenever the temperature drops below freezing overnight, the citrus farmers in the valley run large fans and spray their trees with water to protect the fruit. This year, the fans and sprayers have run every night for the past two weeks.\n\nWhich conclusion is best supported by the passage?","options":["Overnight temperatures have fallen below freezing for the past two weeks.","Spraying trees with water always destroys citrus fruit.","The valley rarely experiences freezing temperatures.","The farmers expect a record harvest this year."],"correct":[0],"explanation":"The farmers use the equipment 'whenever the temperature drops below freezing,' and it has run every night for two weeks, so freezing nights can be inferred. The other options are unsupported or contradict the passage."},
  {"section":"READING","topic":"key-ideas-details","subtopic":"Infer Logical Conclusions From a Text","difficulty":2,"stem":"Read the passage and answer the question.\n\nMaria packed her umbrella, rain boots, and a waterproof jacket before leaving the house. She also moved her morning jog to the indoor track at the gym instead of running through the park as she usually does.\n\nWhat can the reader most reasonably infer?","options":["Maria expected rainy weather that day.","Maria's umbrella was broken.","Maria was going on a long vacation.","Maria dislikes exercising outdoors in any season."],"correct":[0],"explanation":"Packing rain gear and moving her jog indoors point to expected rain. The other options are not supported by the details given."},
  {"section":"READING","topic":"key-ideas-details","subtopic":"Infer Logical Conclusions From a Text","difficulty":3,"stem":"Read the passage and answer the question.\n\nThe new museum exhibit was scheduled to open Saturday, but on Friday afternoon the curator posted a notice canceling the preview event. The crates holding several paintings had not cleared customs, and the gallery walls stood bare.\n\nWhich conclusion is best supported by the passage?","options":["The exhibit could not open as planned because key artworks had not arrived.","The curator no longer wanted to display the paintings.","Visitors had complained about the preview event.","The museum had decided to close permanently."],"correct":[0],"explanation":"The crates of paintings 'had not cleared customs' and the walls were 'bare,' so the missing artworks explain the cancellation. B, C, and D introduce reasons the passage never states."},
  {"section":"READING","topic":"key-ideas-details","subtopic":"Infer Logical Conclusions From a Text","difficulty":1,"stem":"Read the passage and answer the question.\n\nBy the time the guests arrived, Daniel had set the table, lit the candles, and pulled a steaming dish from the oven. The smell of roasted garlic filled the kitchen.\n\nWhat can the reader most reasonably conclude?","options":["Daniel had prepared a meal for his guests.","Daniel had ordered takeout for the evening.","Daniel disliked cooking with garlic.","Daniel was not expecting any visitors."],"correct":[0],"explanation":"Setting the table, lighting candles, and removing a steaming dish from the oven show Daniel cooked a meal for guests. The other choices contradict these details."},
  {"section":"READING","topic":"key-ideas-details","subtopic":"Demonstrate Comprehension of Written Directions","difficulty":1,"stem":"Read the directions and answer the question.\n\nTo brew a cup of loose-leaf tea: (1) Heat water until it just begins to boil. (2) Place one teaspoon of leaves in the strainer. (3) Pour the hot water over the leaves and steep for four minutes. (4) Remove the strainer and discard the leaves before drinking.\n\nAccording to the directions, what should you do immediately after pouring the hot water over the leaves?","options":["Place one teaspoon of leaves in the strainer.","Discard the leaves.","Heat the water until it boils.","Steep the leaves for four minutes."],"correct":[3],"explanation":"Step 3 says to pour the water and then 'steep for four minutes,' so steeping is the next action. The other steps come before pouring or after steeping."},
  {"section":"READING","topic":"key-ideas-details","subtopic":"Demonstrate Comprehension of Written Directions","difficulty":2,"stem":"Read the directions and answer the question.\n\nMedication instructions: Take one tablet by mouth twice daily with food. Do not take more than two tablets in a 24-hour period. If you miss a dose, take it as soon as you remember, unless it is almost time for your next dose. Do not double the dose to make up for a missed one.\n\nA patient realizes she missed a dose, but her next scheduled dose is in 30 minutes. According to the directions, what should she do?","options":["Take two tablets now to catch up.","Take the missed dose now and the next dose in 30 minutes.","Wait 24 hours before taking any tablet.","Skip the missed dose and take only the next scheduled dose."],"correct":[3],"explanation":"The instructions say to take a missed dose when remembered 'unless it is almost time for your next dose,' and not to double up. Because her next dose is imminent, she should skip the missed one and take only the scheduled dose."},
  {"section":"READING","topic":"key-ideas-details","subtopic":"Demonstrate Comprehension of Written Directions","difficulty":2,"stem":"Read the directions and answer the question.\n\nTo assemble the bookshelf: First, attach the two side panels to the base using the four long screws. Next, slide each shelf into the grooves, starting from the bottom. Then secure the back panel with the small nails. Finally, tighten all screws once every piece is in place.\n\nAccording to the directions, when should the back panel be secured?","options":["After the shelves are slid into the grooves.","Before attaching the side panels to the base.","Before sliding any shelves into the grooves.","After tightening all of the screws."],"correct":[0],"explanation":"The order is: side panels, then shelves, then 'secure the back panel,' then tighten screws. So the back panel is secured after the shelves go in and before the final tightening."},
  {"section":"READING","topic":"key-ideas-details","subtopic":"Locate Specific Information in a Text","difficulty":1,"stem":"Read the passage and answer the question.\n\nThe blue whale is the largest animal known to have existed. An adult can reach a length of about 100 feet and weigh as much as 200 tons. Despite its enormous size, the blue whale feeds almost entirely on tiny shrimp-like animals called krill, eating up to four tons of them each day.\n\nAccording to the passage, what does the blue whale eat?","options":["Small fish and squid.","Krill, which are tiny shrimp-like animals.","Ocean plants and seaweed.","Other whales."],"correct":[1],"explanation":"The passage states the blue whale 'feeds almost entirely on tiny shrimp-like animals called krill.' The other options are not mentioned in the text."},
  {"section":"READING","topic":"key-ideas-details","subtopic":"Locate Specific Information in a Text","difficulty":2,"stem":"Read the passage and answer the question.\n\nThe city library expanded its hours last spring. It is now open from 9:00 a.m. to 8:00 p.m. on weekdays and from 10:00 a.m. to 5:00 p.m. on Saturdays. The library remains closed on Sundays and all federal holidays. Patrons may return books at any time using the outdoor drop box.\n\nAccording to the passage, when is the library open on Saturdays?","options":["It is closed on Saturdays.","From 9:00 a.m. to 8:00 p.m.","From 10:00 a.m. to 5:00 p.m.","From 9:00 a.m. to 5:00 p.m."],"correct":[2],"explanation":"The passage states the library is open 'from 10:00 a.m. to 5:00 p.m. on Saturdays.' The 9:00-to-8:00 hours apply to weekdays, and the library is not closed Saturdays."},
  {"section":"READING","topic":"key-ideas-details","subtopic":"Locate Specific Information in a Text","difficulty":2,"stem":"Read the passage and answer the question.\n\nMount Kilimanjaro, located in Tanzania, is the highest mountain in Africa, rising about 19,341 feet above sea level. Unlike many tall peaks, it is not part of a mountain range; it stands alone as a dormant volcano. Thousands of climbers attempt to reach its summit each year, though many turn back because of altitude sickness.\n\nAccording to the passage, why do many climbers turn back?","options":["Because the summit is closed to the public.","Because the volcano is actively erupting.","Because of altitude sickness.","Because the mountain is part of a long range."],"correct":[2],"explanation":"The passage says many climbers 'turn back because of altitude sickness.' The other options contradict the text, which calls the volcano dormant and standing alone."},
  {"section":"READING","topic":"key-ideas-details","subtopic":"Identify Information From a Printed Communication","difficulty":1,"stem":"Read the notice and answer the question.\n\nCOMMUNITY POOL NOTICE\nThe pool will be CLOSED for cleaning on Monday, July 6.\nNormal hours resume Tuesday, July 7: 6:00 a.m. - 9:00 p.m.\nChildren under 12 must be accompanied by an adult at all times.\nQuestions? Call the front desk at 555-0182.\n\nAccording to the notice, on which day is the pool closed?","options":["Tuesday, July 7.","Every day in July.","Sunday, July 5.","Monday, July 6."],"correct":[3],"explanation":"The notice states the pool will be 'CLOSED for cleaning on Monday, July 6.' Tuesday is when normal hours resume, and the other dates are not mentioned."},
  {"section":"READING","topic":"key-ideas-details","subtopic":"Identify Information From a Printed Communication","difficulty":2,"stem":"Read the email and answer the question.\n\nTo: All Staff\nFrom: Human Resources\nSubject: Parking Lot Repaving\n\nThe north parking lot will be repaved starting Wednesday and will be unavailable for two days. During this time, please use the south lot or the street garage on Elm Avenue. Shuttle service to the main entrance will run every 15 minutes from the Elm Avenue garage.\n\nAccording to the email, where can staff park while the north lot is closed?","options":["In the south lot or the Elm Avenue garage.","Only on the street outside the building.","In the north lot, using the shuttle.","Nowhere; staff must work from home."],"correct":[0],"explanation":"The email instructs staff to 'use the south lot or the street garage on Elm Avenue' while the north lot is repaved. The other options misread or contradict the message."},
  {"section":"READING","topic":"key-ideas-details","subtopic":"Identify Information From a Printed Communication","difficulty":2,"stem":"Read the appointment card and answer the question.\n\nWESTSIDE DENTAL\nPatient: J. Ortiz\nAppointment: Thursday, August 13, at 2:30 p.m.\nReason: Routine cleaning\nPlease arrive 15 minutes early to update your insurance information.\nTo reschedule, call at least 24 hours in advance.\n\nAccording to the card, what time should the patient arrive at the office?","options":["2:15 p.m.","2:30 p.m.","2:45 p.m.","1:30 p.m."],"correct":[0],"explanation":"The appointment is at 2:30 p.m., and the card asks the patient to 'arrive 15 minutes early,' which is 2:15 p.m. 2:30 is the appointment time itself, and the other times do not match the instruction."},
  {"section":"READING","topic":"key-ideas-details","subtopic":"Identify Information From a Graphic","difficulty":1,"stem":"Use the table to answer the question.\n\nDaily Rainfall (in inches)\nMonday: 0.2\nTuesday: 1.1\nWednesday: 0.0\nThursday: 0.5\nFriday: 0.8\n\nAccording to the table, which day had the most rainfall?","options":["Friday","Tuesday","Monday","Thursday"],"correct":[1],"explanation":"Tuesday recorded 1.1 inches, the highest value in the table. Friday (0.8) is the next highest, and the other days are lower."},
  {"section":"READING","topic":"key-ideas-details","subtopic":"Identify Information From a Graphic","difficulty":2,"stem":"Use the bus schedule to answer the question.\n\nROUTE 9 DEPARTURES (from Central Station)\n7:00 a.m. - Express to Airport\n7:20 a.m. - Local to Downtown\n7:45 a.m. - Express to Airport\n8:10 a.m. - Local to Downtown\n8:30 a.m. - Express to Airport\n\nA passenger arrives at Central Station at 7:25 a.m. and needs an Express bus to the Airport. According to the schedule, what is the next departure she can take?","options":["7:45 a.m.","8:10 a.m.","7:00 a.m.","7:20 a.m."],"correct":[0],"explanation":"After 7:25 a.m., the next Express to the Airport leaves at 7:45 a.m. The 7:20 and 7:00 departures already left, and 8:10 is a Local to Downtown, not an Express."},
  {"section":"READING","topic":"key-ideas-details","subtopic":"Identify Information From a Graphic","difficulty":3,"stem":"Use the nutrition label to answer the question.\n\nNUTRITION FACTS (per serving)\nServings per container: 3\nCalories: 150\nTotal Fat: 6 g\nSodium: 200 mg\nTotal Carbohydrate: 22 g\nProtein: 4 g\n\nIf a person eats the entire container, how many grams of total carbohydrate will they consume?","options":["44 g","66 g","11 g","22 g"],"correct":[1],"explanation":"Each serving has 22 g of carbohydrate, and the container holds 3 servings, so 22 x 3 = 66 g. The 22 g figure is for a single serving only."},
  {"section":"READING","topic":"key-ideas-details","subtopic":"Interpret Events in a Sequence","difficulty":2,"stem":"Read the passage and answer the question.\n\nLena first sketched the design on paper. After she was satisfied with the drawing, she selected her fabrics and cut out each piece. She then sewed the pieces together and, last of all, stitched a label with her initials onto the finished bag.\n\nAccording to the passage, what did Lena do right before sewing the pieces together?","options":["She cut out each piece of fabric.","She sketched the design on paper.","She sold the finished bag.","She stitched on a label with her initials."],"correct":[0],"explanation":"The order is sketch, select and cut fabric, then sew. So cutting out the pieces happened just before sewing them together. Sketching was earlier and the label came last."},
  {"section":"READING","topic":"key-ideas-details","subtopic":"Interpret Events in a Sequence","difficulty":2,"type":"ORDERED","stem":"Read the passage and arrange the events in the order they occurred.\n\nThe storm began as a calm afternoon turned dark. First, thick clouds gathered over the hills. Then a strong wind bent the trees and scattered leaves across the yard. Rain followed, falling harder by the minute. At last, a bright flash of lightning lit the sky, and thunder rolled through the valley.\n\nArrange these events in chronological order:","options":["Lightning flashes and thunder rolls.","A strong wind bends the trees.","Thick clouds gather over the hills.","Rain falls harder by the minute."],"correct":[2,1,3,0],"explanation":"The passage gives the sequence explicitly: clouds gather 'first,' then wind, then rain, and 'at last' lightning and thunder. The listed order matches that chronology."},
  {"section":"READING","topic":"key-ideas-details","subtopic":"Interpret Events in a Sequence","difficulty":3,"stem":"Read the passage and answer the question.\n\nThe recipe came together quickly. Before turning on the oven, Marcus greased the pan. He preheated the oven only after the batter was fully mixed. Once the oven reached temperature, he poured in the batter and baked the cake for thirty minutes.\n\nAccording to the passage, which event happened first?","options":["Marcus greased the pan.","Marcus mixed the batter.","Marcus preheated the oven.","Marcus poured in the batter."],"correct":[0],"explanation":"The passage says he greased the pan 'before turning on the oven,' and he preheated only after mixing the batter. Greasing the pan is therefore the earliest event listed."},
  {"section":"MATH","topic":"measurement-data","subtopic":"Interpret Relevant Information from Tables, Charts, and Graphs","difficulty":1,"stem":"A bookstore recorded the number of books sold each day:\nMon: 12, Tue: 8, Wed: 15, Thu: 9, Fri: 21.\nOn which day were the most books sold?","options":["Tuesday","Friday","Wednesday","Thursday"],"correct":[1],"explanation":"Comparing the values, Friday's 21 books is the largest, so the most books were sold on Friday."},
  {"section":"MATH","topic":"measurement-data","subtopic":"Interpret Relevant Information from Tables, Charts, and Graphs","difficulty":2,"stem":"A dealership recorded cars sold by month:\nJan: 30, Feb: 45, Mar: 25, Apr: 50.\nHow many more cars were sold in April than in March?","options":["15","20","75","25"],"correct":[3],"explanation":"Subtract March from April: 50 − 25 = 25 cars more."},
  {"section":"MATH","topic":"measurement-data","subtopic":"Interpret Relevant Information from Tables, Charts, and Graphs","difficulty":2,"type":"FILL_BLANK","stem":"Daily rainfall (in inches) for one week was recorded:\nMon: 0.5, Tue: 1.2, Wed: 0.0, Thu: 0.8, Fri: 1.5.\nWhat was the total rainfall for the week, in inches?","options":[],"correct":["4","4.0","4 inches","4.0 inches"],"explanation":"Add all values: 0.5 + 1.2 + 0.0 + 0.8 + 1.5 = 4.0 inches."},
  {"section":"MATH","topic":"measurement-data","subtopic":"Interpret Relevant Information from Tables, Charts, and Graphs","difficulty":2,"stem":"A class's final grades are shown in this frequency table:\nA: 6, B: 10, C: 8, D: 3, F: 1.\nHow many students earned a grade of C or higher (A, B, or C)?","options":["18","24","28","16"],"correct":[1],"explanation":"Add the A, B, and C counts: 6 + 10 + 8 = 24 students."},
  {"section":"MATH","topic":"measurement-data","subtopic":"Interpret Relevant Information from Tables, Charts, and Graphs","difficulty":1,"stem":"A nurse recorded a patient's temperature (°F) over time:\n8 AM: 65, 10 AM: 70, 12 PM: 72, 2 PM: 75.\n(Values are example readings.) At what time was the reading 72?","options":["2 PM","12 PM","8 AM","10 AM"],"correct":[1],"explanation":"The table shows a reading of 72 at 12 PM."},
  {"section":"MATH","topic":"measurement-data","subtopic":"Evaluate Information in Tables, Charts, and Graphs Using Statistics","difficulty":2,"stem":"A student's five test scores were: 80, 85, 90, 95, 100. What is the mean (average) score?","options":["95","85","90","92"],"correct":[2],"explanation":"Add the scores and divide by 5: (80 + 85 + 90 + 95 + 100) ÷ 5 = 450 ÷ 5 = 90."},
  {"section":"MATH","topic":"measurement-data","subtopic":"Evaluate Information in Tables, Charts, and Graphs Using Statistics","difficulty":1,"stem":"What is the median of the following data set?\n3, 8, 2, 10, 5","options":["8","5","6","5.6"],"correct":[1],"explanation":"Order the values: 2, 3, 5, 8, 10. The middle value is 5, so the median is 5. (The mean would be 5.6.)"},
  {"section":"MATH","topic":"measurement-data","subtopic":"Evaluate Information in Tables, Charts, and Graphs Using Statistics","difficulty":1,"stem":"What is the mode of the following data set?\n4, 7, 7, 2, 9, 7, 3","options":["3","4","7","9"],"correct":[2],"explanation":"The mode is the value that appears most often. The number 7 appears three times, more than any other value."},
  {"section":"MATH","topic":"measurement-data","subtopic":"Evaluate Information in Tables, Charts, and Graphs Using Statistics","difficulty":2,"type":"FILL_BLANK","stem":"A data set of weekly sales totals is: 15, 22, 8, 30, 19. What is the range of the data set?","options":[],"correct":["22"],"explanation":"The range is the largest value minus the smallest value: 30 − 8 = 22."},
  {"section":"MATH","topic":"measurement-data","subtopic":"Evaluate Information in Tables, Charts, and Graphs Using Statistics","difficulty":2,"stem":"The hours worked by 5 employees in one week are shown:\nEmployee 1: 38, Employee 2: 40, Employee 3: 42, Employee 4: 36, Employee 5: 44.\nWhat is the mean number of hours worked?","options":["42","41","40","38"],"correct":[2],"explanation":"Add all hours and divide by 5: (38 + 40 + 42 + 36 + 44) ÷ 5 = 200 ÷ 5 = 40 hours."},
  {"section":"MATH","topic":"measurement-data","subtopic":"Explain the Relationship Between Variables","difficulty":2,"stem":"A table shows hours studied and test score:\n1 hr: 60, 2 hr: 70, 3 hr: 80, 4 hr: 90.\nIf the pattern continues, what score is predicted for 5 hours of studying?","options":["95","90","110","100"],"correct":[3],"explanation":"The score increases by 10 for each additional hour, so 90 + 10 = 100 for 5 hours."},
  {"section":"MATH","topic":"measurement-data","subtopic":"Explain the Relationship Between Variables","difficulty":2,"stem":"A café tracked the outdoor temperature and cups of hot chocolate sold:\n30°F: 50 cups, 40°F: 40 cups, 50°F: 30 cups, 60°F: 20 cups.\nWhich statement best describes the relationship?","options":["There is no relationship between temperature and cups sold.","As temperature increases, cups sold increase.","As temperature increases, cups sold decrease.","Cups sold remain the same as temperature increases."],"correct":[2],"explanation":"As temperature rises from 30°F to 60°F, cups sold fall from 50 to 20, so as temperature increases, cups sold decrease (a negative relationship)."},
  {"section":"MATH","topic":"measurement-data","subtopic":"Explain the Relationship Between Variables","difficulty":2,"stem":"A car travels at a constant speed. A table of time and distance shows:\n2 hr: 120 mi, 3 hr: 180 mi, 4 hr: 240 mi.\nHow far will the car travel in 6 hours?","options":["240 miles","300 miles","360 miles","420 miles"],"correct":[2],"explanation":"The constant rate is 120 ÷ 2 = 60 miles per hour, so in 6 hours: 60 × 6 = 360 miles."},
  {"section":"MATH","topic":"measurement-data","subtopic":"Explain the Relationship Between Variables","difficulty":2,"stem":"A cookie recipe is proportional: 2 cups of flour make 12 cookies. How many cups of flour are needed to make 30 cookies?","options":["4 cups","5 cups","6 cups","15 cups"],"correct":[1],"explanation":"Each cup makes 12 ÷ 2 = 6 cookies. To make 30 cookies: 30 ÷ 6 = 5 cups of flour."},
  {"section":"MATH","topic":"measurement-data","subtopic":"Calculate Geometric Quantities","difficulty":1,"stem":"A rectangle has a length of 8 cm and a width of 5 cm. What is its area?","options":["80 cm²","40 cm²","26 cm²","13 cm²"],"correct":[1],"explanation":"Area of a rectangle = length × width = 8 × 5 = 40 cm²."},
  {"section":"MATH","topic":"measurement-data","subtopic":"Calculate Geometric Quantities","difficulty":2,"stem":"A circle has a radius of 5 cm. Using π ≈ 3.14, what is the area of the circle?","options":["31.4 cm²","78.5 cm²","314 cm²","15.7 cm²"],"correct":[1],"explanation":"Area = π × r² = 3.14 × 5² = 3.14 × 25 = 78.5 cm²."},
  {"section":"MATH","topic":"measurement-data","subtopic":"Calculate Geometric Quantities","difficulty":2,"stem":"A circle has a diameter of 10 cm. Using π ≈ 3.14, what is its circumference?","options":["62.8 cm","78.5 cm","31.4 cm","15.7 cm"],"correct":[2],"explanation":"Circumference = π × diameter = 3.14 × 10 = 31.4 cm."},
  {"section":"MATH","topic":"measurement-data","subtopic":"Calculate Geometric Quantities","difficulty":2,"stem":"A rectangular box has a length of 4 cm, a width of 3 cm, and a height of 2 cm. What is its volume?","options":["9 cm³","26 cm³","12 cm³","24 cm³"],"correct":[3],"explanation":"Volume = length × width × height = 4 × 3 × 2 = 24 cm³."},
  {"section":"MATH","topic":"measurement-data","subtopic":"Calculate Geometric Quantities","difficulty":2,"stem":"A triangle has a base of 10 cm and a height of 6 cm. What is its area?","options":["30 cm²","60 cm²","16 cm²","15 cm²"],"correct":[0],"explanation":"Area of a triangle = ½ × base × height = ½ × 10 × 6 = 30 cm²."},
  {"section":"MATH","topic":"measurement-data","subtopic":"Convert Within and Between Standard and Metric Units","difficulty":1,"stem":"A board is 5 feet long. How many inches long is it? (1 ft = 12 in)","options":["600 in","60 in","50 in","17 in"],"correct":[1],"explanation":"Multiply feet by 12: 5 × 12 = 60 inches."},
  {"section":"MATH","topic":"measurement-data","subtopic":"Convert Within and Between Standard and Metric Units","difficulty":2,"type":"FILL_BLANK","stem":"A package has a mass of 2.5 kg. About how many pounds is this? (1 kg ≈ 2.2 lb)","options":[],"correct":["5.5","5.5 lb","5.5 pounds"],"explanation":"Multiply kilograms by 2.2: 2.5 × 2.2 = 5.5 lb."},
  {"section":"MATH","topic":"measurement-data","subtopic":"Convert Within and Between Standard and Metric Units","difficulty":1,"stem":"A container holds 3 liters of solution. How many milliliters is this? (1 L = 1000 mL)","options":["30,000 mL","30 mL","300 mL","3000 mL"],"correct":[3],"explanation":"Multiply liters by 1000: 3 × 1000 = 3000 mL."},
  {"section":"MATH","topic":"measurement-data","subtopic":"Convert Within and Between Standard and Metric Units","difficulty":2,"stem":"A ribbon is 10 inches long. How many centimeters is this? (1 in = 2.54 cm)","options":["3.94 cm","12.54 cm","25.4 cm","254 cm"],"correct":[2],"explanation":"Multiply inches by 2.54: 10 × 2.54 = 25.4 cm."},
  {"section":"MATH","topic":"measurement-data","subtopic":"Convert Within and Between Standard and Metric Units","difficulty":1,"stem":"A dose weighs 5000 grams. How many kilograms is this? (1 kg = 1000 g)","options":["500 kg","5 kg","0.5 kg","50 kg"],"correct":[1],"explanation":"Divide grams by 1000: 5000 ÷ 1000 = 5 kg."},
  {"section":"MATH","topic":"numbers-algebra","subtopic":"Perform Arithmetic Operations with Rational Numbers (Whole Numbers, Decimals, & Fractions)","difficulty":1,"stem":"What is 3/4 + 1/6?","options":["11/12","2/5","5/12","4/10"],"correct":[0],"explanation":"Using a common denominator of 12: 3/4 = 9/12 and 1/6 = 2/12, so 9/12 + 2/12 = 11/12. (Adding numerators and denominators directly gives the wrong 4/10.)"},
  {"section":"MATH","topic":"numbers-algebra","subtopic":"Perform Arithmetic Operations with Rational Numbers (Whole Numbers, Decimals, & Fractions)","difficulty":2,"stem":"Evaluate: 2.5 − 0.375 × 4","options":["8.5","1","0.625","1.5"],"correct":[1],"explanation":"By order of operations multiply first: 0.375 × 4 = 1.5, then 2.5 − 1.5 = 1. (Subtracting first gives the incorrect 8.5.)"},
  {"section":"MATH","topic":"numbers-algebra","subtopic":"Perform Arithmetic Operations with Rational Numbers (Whole Numbers, Decimals, & Fractions)","difficulty":2,"stem":"What is −3/8 ÷ 3/4?","options":["−2","−1/2","−9/32","1/2"],"correct":[1],"explanation":"Dividing by a fraction means multiplying by its reciprocal: −3/8 × 4/3 = −12/24 = −1/2. (Multiplying straight across gives the incorrect −9/32.)"},
  {"section":"MATH","topic":"numbers-algebra","subtopic":"Perform Arithmetic Operations with Rational Numbers (Whole Numbers, Decimals, & Fractions)","difficulty":3,"type":"FILL_BLANK","stem":"What is 1¾ + 2⅔? Write your answer as a mixed number in simplest form.","options":[],"correct":["4 5/12","53/12","4-5/12"],"explanation":"Convert to improper fractions: 7/4 + 8/3 = 21/12 + 32/12 = 53/12 = 4 5/12."},
  {"section":"MATH","topic":"numbers-algebra","subtopic":"Convert Among Decimals, Fractions & Percents","difficulty":1,"stem":"Write 0.6 as a fraction in simplest form.","options":["1/6","3/5","2/3","6/10"],"correct":[1],"explanation":"0.6 = 6/10, and dividing numerator and denominator by 2 gives 3/5."},
  {"section":"MATH","topic":"numbers-algebra","subtopic":"Convert Among Decimals, Fractions & Percents","difficulty":2,"stem":"What is 5/8 written as a percent?","options":["0.625%","58%","37.5%","62.5%"],"correct":[3],"explanation":"5 ÷ 8 = 0.625, and 0.625 × 100 = 62.5%."},
  {"section":"MATH","topic":"numbers-algebra","subtopic":"Convert Among Decimals, Fractions & Percents","difficulty":2,"type":"FILL_BLANK","stem":"Express 45% as a fraction in simplest form.","options":[],"correct":["9/20"],"explanation":"45% = 45/100, and dividing numerator and denominator by 5 gives 9/20."},
  {"section":"MATH","topic":"numbers-algebra","subtopic":"Solve Real World Problems Involving Percents","difficulty":2,"stem":"A jacket regularly priced at $80 is on sale for 25% off. What is the sale price?","options":["$55","$20","$75","$60"],"correct":[3],"explanation":"The discount is 0.25 × $80 = $20, so the sale price is $80 − $20 = $60 (equivalently 0.75 × $80)."},
  {"section":"MATH","topic":"numbers-algebra","subtopic":"Solve Real World Problems Involving Percents","difficulty":2,"stem":"A restaurant bill is $48.00. How much is a 15% tip on the bill?","options":["$72.00","$6.40","$7.00","$7.20"],"correct":[3],"explanation":"0.15 × $48.00 = $7.20."},
  {"section":"MATH","topic":"numbers-algebra","subtopic":"Solve Real World Problems Involving Percents","difficulty":3,"stem":"A town's population grew from 250 people to 320 people. What is the percent increase?","options":["28%","21.9%","22%","70%"],"correct":[0],"explanation":"The increase is 320 − 250 = 70, and 70 ÷ 250 = 0.28 = 28%. (Dividing by 320 instead of the original gives the incorrect 21.9%.)"},
  {"section":"MATH","topic":"numbers-algebra","subtopic":"Solve Real World Problems Involving Percents","difficulty":3,"stem":"After a 20% discount, a coat costs $48. What was the original price?","options":["$68","$60","$240","$57.60"],"correct":[1],"explanation":"The sale price is 80% of the original: 0.80 × original = $48, so original = $48 ÷ 0.80 = $60. (Adding 20% to $48 gives the incorrect $57.60.)"},
  {"section":"MATH","topic":"numbers-algebra","subtopic":"Compare & Order Rational Numbers","difficulty":1,"stem":"Which of the following has the greatest value?","options":["1/3","0.5","0.45","2/5"],"correct":[1],"explanation":"As decimals: 0.5, 1/3 ≈ 0.33, 2/5 = 0.4, and 0.45. The largest is 0.5."},
  {"section":"MATH","topic":"numbers-algebra","subtopic":"Compare & Order Rational Numbers","difficulty":2,"stem":"Order these numbers from least to greatest: 3/5, 0.55, 7/10.","options":["7/10, 3/5, 0.55","0.55, 7/10, 3/5","3/5, 0.55, 7/10","0.55, 3/5, 7/10"],"correct":[3],"explanation":"As decimals: 3/5 = 0.6, 0.55, and 7/10 = 0.7. From least to greatest: 0.55, 3/5, 7/10."},
  {"section":"MATH","topic":"numbers-algebra","subtopic":"Compare & Order Rational Numbers","difficulty":2,"stem":"Which number is less than −2/3?","options":["−3/4","−0.6","−0.5","−1/2"],"correct":[0],"explanation":"−2/3 ≈ −0.667. Since −3/4 = −0.75 is farther below zero, it is less than −2/3; the others are greater."},
  {"section":"MATH","topic":"numbers-algebra","subtopic":"Solve Equations in One Variable","difficulty":1,"stem":"Solve for x: 3x + 5 = 20","options":["5","9","15","45"],"correct":[0],"explanation":"Subtract 5 from both sides: 3x = 15, then divide by 3 to get x = 5."},
  {"section":"MATH","topic":"numbers-algebra","subtopic":"Solve Equations in One Variable","difficulty":2,"stem":"Solve for x: 2(x − 4) = 10","options":["18","9","7","1"],"correct":[1],"explanation":"Distribute: 2x − 8 = 10, so 2x = 18 and x = 9. (Failing to distribute to the 4 gives the incorrect 7.)"},
  {"section":"MATH","topic":"numbers-algebra","subtopic":"Solve Equations in One Variable","difficulty":2,"stem":"Solve for x: x/3 − 2 = 4","options":["6","12","18","2"],"correct":[2],"explanation":"Add 2 to both sides: x/3 = 6, then multiply by 3 to get x = 18."},
  {"section":"MATH","topic":"numbers-algebra","subtopic":"Solve Equations in One Variable","difficulty":3,"type":"FILL_BLANK","stem":"Solve for x: 5x − 3 = 2x + 12","options":[],"correct":["5"],"explanation":"Subtract 2x from both sides: 3x − 3 = 12, then add 3 to get 3x = 15, so x = 5."},
  {"section":"MATH","topic":"numbers-algebra","subtopic":"Apply Estimation Strategies and Rounding Rules to Real World Problems","difficulty":1,"stem":"Round 4,827 to the nearest hundred.","options":["4,830","4,900","4,800","5,000"],"correct":[2],"explanation":"The tens digit is 2 (less than 5), so the hundreds digit stays 8 and the number rounds down to 4,800."},
  {"section":"MATH","topic":"numbers-algebra","subtopic":"Apply Estimation Strategies and Rounding Rules to Real World Problems","difficulty":2,"stem":"Estimate the product 38 × 21 by first rounding each factor to the nearest ten.","options":["600","800","798","760"],"correct":[1],"explanation":"Round 38 to 40 and 21 to 20: 40 × 20 = 800."},
  {"section":"MATH","topic":"numbers-algebra","subtopic":"Apply Estimation Strategies and Rounding Rules to Real World Problems","difficulty":2,"stem":"A car travels 296 miles on 11.8 gallons of gas. Estimate the miles per gallon by rounding to convenient numbers.","options":["30","25","27","20"],"correct":[1],"explanation":"Round 296 to 300 and 11.8 to 12: 300 ÷ 12 = 25 miles per gallon."},
  {"section":"MATH","topic":"numbers-algebra","subtopic":"Solve Real World Problems Involving Proportions, Ratios, and Rates of Change","difficulty":2,"stem":"If 3 apples cost $1.80, how much do 7 apples cost at the same rate?","options":["$4.20","$4.00","$5.40","$3.60"],"correct":[0],"explanation":"The unit price is $1.80 ÷ 3 = $0.60 per apple, so 7 apples cost 7 × $0.60 = $4.20."},
  {"section":"MATH","topic":"numbers-algebra","subtopic":"Solve Real World Problems Involving Proportions, Ratios, and Rates of Change","difficulty":2,"stem":"A recipe uses flour and sugar in a ratio of 5:2. If 15 cups of flour are used, how many cups of sugar are needed?","options":["7.5","10","6","3"],"correct":[2],"explanation":"15 cups of flour is 15 ÷ 5 = 3 times the ratio amount, so sugar = 3 × 2 = 6 cups."},
  {"section":"MATH","topic":"numbers-algebra","subtopic":"Solve Real World Problems Involving Proportions, Ratios, and Rates of Change","difficulty":3,"type":"FILL_BLANK","stem":"On a map, 1 inch represents 25 miles. Two cities are 4.5 inches apart on the map. How many actual miles apart are they?","options":[],"correct":["112.5","112 1/2","112.50"],"explanation":"Multiply the map distance by the scale: 4.5 × 25 = 112.5 miles."},
  {"section":"MATH","topic":"numbers-algebra","subtopic":"Translate Phrases and Sentences into Expressions, Equations, and Inequalities","difficulty":1,"stem":"Which expression represents \"five less than three times a number n\"?","options":["3(n − 5)","5 − 3n","3n − 5","5n − 3"],"correct":[2],"explanation":"\"Three times a number\" is 3n, and \"five less than\" that means subtracting 5: 3n − 5."},
  {"section":"MATH","topic":"numbers-algebra","subtopic":"Translate Phrases and Sentences into Expressions, Equations, and Inequalities","difficulty":2,"stem":"Which inequality represents \"the sum of a number x and 8 is at least 15\"?","options":["8 − x ≥ 15","x + 8 ≤ 15","x + 8 > 15","x + 8 ≥ 15"],"correct":[3],"explanation":"\"The sum of a number and 8\" is x + 8, and \"at least 15\" means greater than or equal to 15: x + 8 ≥ 15."},
  {"section":"SCIENCE","topic":"anatomy-physiology","subtopic":"Demonstrate Knowledge of the General Orientation of Human Anatomy","difficulty":1,"stem":"In standard anatomical position, which directional term correctly describes the position of the wrist relative to the elbow?","options":["Medial","Proximal","Distal","Superior"],"correct":[2],"explanation":"Distal means farther from the point of attachment to the trunk; the wrist is farther down the arm than the elbow, so it is distal. Proximal is the opposite (closer to the trunk), and superior/medial describe up-down and toward-the-midline relationships, not relative limb distance."},
  {"section":"SCIENCE","topic":"anatomy-physiology","subtopic":"Demonstrate Knowledge of the General Orientation of Human Anatomy","difficulty":2,"stem":"A plane that divides the body into superior and inferior portions is called the:","options":["Sagittal plane","Midsagittal plane","Frontal (coronal) plane","Transverse plane"],"correct":[3],"explanation":"The transverse (horizontal) plane cuts the body into upper (superior) and lower (inferior) parts. The sagittal plane divides into left and right, and the frontal/coronal plane divides into anterior and posterior portions."},
  {"section":"SCIENCE","topic":"anatomy-physiology","subtopic":"Demonstrate Knowledge of the General Orientation of Human Anatomy","difficulty":2,"stem":"The diaphragm separates which two body cavities?","options":["Abdominal and pelvic cavities","Pleural and pericardial cavities","Cranial and spinal cavities","Thoracic and abdominal cavities"],"correct":[3],"explanation":"The muscular diaphragm forms the floor of the thoracic cavity and the roof of the abdominal cavity, separating the two. The pleural and pericardial cavities are subdivisions within the thorax, and the abdominal and pelvic cavities are continuous (together the abdominopelvic cavity)."},
  {"section":"SCIENCE","topic":"anatomy-physiology","subtopic":"Respiratory System","difficulty":1,"stem":"Gas exchange between air and blood occurs primarily in which structures of the lungs?","options":["Alveoli","Bronchioles","Trachea","Bronchi"],"correct":[0],"explanation":"The alveoli are thin-walled sacs surrounded by capillaries where oxygen and carbon dioxide diffuse between air and blood. The trachea, bronchi, and bronchioles are conducting airways that move air but do not perform significant gas exchange."},
  {"section":"SCIENCE","topic":"anatomy-physiology","subtopic":"Respiratory System","difficulty":2,"stem":"During quiet inhalation, the diaphragm contracts and moves downward. What effect does this have on thoracic volume and pressure?","options":["Volume and pressure both decrease","Volume and pressure both increase","Volume decreases and pressure increases","Volume increases and pressure decreases"],"correct":[3],"explanation":"Diaphragm contraction enlarges the thoracic cavity, increasing volume; by Boyle's law, increased volume lowers intrapulmonary pressure below atmospheric pressure, so air flows in. Exhalation reverses this (volume down, pressure up)."},
  {"section":"SCIENCE","topic":"anatomy-physiology","subtopic":"Respiratory System","difficulty":3,"stem":"Most carbon dioxide is transported in the blood in which form?","options":["Bound to hemoglobin as carbaminohemoglobin","Bound to plasma albumin","As bicarbonate ions (HCO3-) in plasma","Dissolved in plasma as CO2 gas"],"correct":[2],"explanation":"About 70% of CO2 is carried as bicarbonate ions formed when CO2 combines with water in red blood cells. Roughly 20-23% binds hemoglobin as carbaminohemoglobin and only about 7-10% is dissolved directly in plasma."},
  {"section":"SCIENCE","topic":"anatomy-physiology","subtopic":"Cardiovascular System","difficulty":2,"stem":"Which sequence correctly traces blood flow through the heart starting at the right atrium?","options":["Right atrium, left atrium, aorta, lungs","Right atrium, right ventricle, pulmonary artery, lungs","Right atrium, right ventricle, pulmonary vein, lungs","Right atrium, left ventricle, aorta, body"],"correct":[1],"explanation":"Deoxygenated blood enters the right atrium, passes to the right ventricle, then exits via the pulmonary artery to the lungs. Pulmonary veins (not artery) return oxygenated blood to the left atrium, and the aorta carries blood from the left ventricle to the body."},
  {"section":"SCIENCE","topic":"anatomy-physiology","subtopic":"Cardiovascular System","difficulty":1,"stem":"Which type of blood vessel carries blood away from the heart?","options":["Arteries","Veins","Venules","Capillaries"],"correct":[0],"explanation":"Arteries carry blood away from the heart, typically under high pressure. Veins return blood to the heart, capillaries are exchange vessels, and venules are small vessels that drain capillaries into veins."},
  {"section":"SCIENCE","topic":"anatomy-physiology","subtopic":"Cardiovascular System","difficulty":3,"stem":"Which structure of the heart's conduction system normally functions as the primary pacemaker that initiates each heartbeat?","options":["Sinoatrial (SA) node","Bundle of His","Atrioventricular (AV) node","Purkinje fibers"],"correct":[0],"explanation":"The sinoatrial (SA) node in the right atrium spontaneously depolarizes fastest and sets the heart rate. The AV node, bundle of His, and Purkinje fibers relay and distribute the impulse but normally follow the SA node's pace."},
  {"section":"SCIENCE","topic":"anatomy-physiology","subtopic":"Gastrointestinal System","difficulty":2,"stem":"Which organ is the primary site for the absorption of nutrients into the bloodstream?","options":["Stomach","Esophagus","Large intestine","Small intestine"],"correct":[3],"explanation":"The small intestine, with its villi and microvilli, provides a huge surface area where most nutrient absorption occurs. The stomach mainly digests, the large intestine absorbs water and electrolytes, and the esophagus only transports food."},
  {"section":"SCIENCE","topic":"anatomy-physiology","subtopic":"Gastrointestinal System","difficulty":2,"stem":"Bile, which emulsifies fats, is produced by the liver and stored and concentrated in which organ?","options":["Duodenum","Pancreas","Spleen","Gallbladder"],"correct":[3],"explanation":"The gallbladder stores and concentrates bile produced by the liver and releases it into the small intestine. The pancreas secretes digestive enzymes and bicarbonate, the spleen is part of the immune/lymphatic system, and the duodenum receives bile but does not store it."},
  {"section":"SCIENCE","topic":"anatomy-physiology","subtopic":"Gastrointestinal System","difficulty":3,"stem":"The enzyme pepsin, which begins protein digestion in the stomach, requires which condition to function optimally?","options":["An alkaline (high pH) environment","A highly acidic (low pH) environment","The presence of bile salts","A neutral pH near 7"],"correct":[1],"explanation":"Pepsin is activated from pepsinogen and works best in the strongly acidic environment created by stomach hydrochloric acid (around pH 1.5-2). Pancreatic enzymes in the small intestine instead require an alkaline environment, and bile salts emulsify fats rather than activate pepsin."},
  {"section":"SCIENCE","topic":"anatomy-physiology","subtopic":"Neuromuscular System","difficulty":2,"stem":"Which neurotransmitter is released at the neuromuscular junction to trigger skeletal muscle contraction?","options":["Dopamine","Norepinephrine","Serotonin","Acetylcholine"],"correct":[3],"explanation":"Motor neurons release acetylcholine at the neuromuscular junction, which binds receptors on the muscle fiber to initiate contraction. Dopamine, norepinephrine, and serotonin are neurotransmitters acting elsewhere in the nervous system, not at the skeletal neuromuscular junction."},
  {"section":"SCIENCE","topic":"anatomy-physiology","subtopic":"Neuromuscular System","difficulty":3,"stem":"During skeletal muscle contraction, the direct trigger that exposes the binding sites on actin is the release of which ion into the sarcoplasm?","options":["Sodium (Na+)","Chloride (Cl-)","Calcium (Ca2+)","Potassium (K+)"],"correct":[2],"explanation":"Calcium released from the sarcoplasmic reticulum binds troponin, shifting tropomyosin to expose actin's myosin-binding sites. Sodium and potassium drive the action potential along the membrane, but it is calcium that directly initiates cross-bridge formation."},
  {"section":"SCIENCE","topic":"anatomy-physiology","subtopic":"Neuromuscular System","difficulty":1,"stem":"Which part of a neuron typically receives incoming signals from other neurons?","options":["Axon","Myelin sheath","Axon terminal","Dendrites"],"correct":[3],"explanation":"Dendrites are branched extensions that receive signals and carry them toward the cell body. The axon conducts impulses away from the cell body, the axon terminal transmits signals to the next cell, and the myelin sheath insulates the axon."},
  {"section":"SCIENCE","topic":"anatomy-physiology","subtopic":"Reproductive System","difficulty":2,"stem":"In the male reproductive system, sperm are produced in which structure?","options":["Epididymis","Prostate gland","Vas deferens","Seminiferous tubules of the testes"],"correct":[3],"explanation":"Spermatogenesis occurs in the seminiferous tubules of the testes. The epididymis stores and matures sperm, the vas deferens transports them, and the prostate contributes fluid to semen but does not produce sperm."},
  {"section":"SCIENCE","topic":"anatomy-physiology","subtopic":"Reproductive System","difficulty":2,"stem":"In the female reproductive system, fertilization of an egg by a sperm normally occurs in the:","options":["Uterus","Fallopian tube (oviduct)","Cervix","Ovary"],"correct":[1],"explanation":"Fertilization typically occurs in the fallopian tube (oviduct) as the egg travels toward the uterus. The ovary releases the egg, the uterus is where implantation occurs, and the cervix is the lower opening of the uterus."},
  {"section":"SCIENCE","topic":"anatomy-physiology","subtopic":"Integumentary System","difficulty":1,"stem":"Which layer of the skin is the outermost and forms a protective barrier against the environment?","options":["Fascia","Hypodermis (subcutaneous layer)","Dermis","Epidermis"],"correct":[3],"explanation":"The epidermis is the outermost skin layer and provides a protective barrier. The dermis lies beneath it containing blood vessels and nerves, and the hypodermis (subcutaneous layer) lies deeper still, anchoring skin and storing fat."},
  {"section":"SCIENCE","topic":"anatomy-physiology","subtopic":"Integumentary System","difficulty":3,"stem":"When body temperature rises, which integumentary response helps cool the body?","options":["Constriction of dermal blood vessels","Contraction of arrector pili muscles","Activation of sweat glands and dilation of dermal blood vessels","Decreased blood flow to the skin"],"correct":[2],"explanation":"Sweat glands secrete fluid that evaporates and cools the skin, while dilation of dermal blood vessels brings warm blood to the surface to release heat. Vasoconstriction and arrector pili contraction (goosebumps) instead conserve heat when the body is cold."},
  {"section":"SCIENCE","topic":"anatomy-physiology","subtopic":"Endocrine System","difficulty":2,"stem":"Which gland is often called the 'master gland' because it secretes hormones that regulate several other endocrine glands?","options":["Pituitary gland","Adrenal gland","Thyroid gland","Pineal gland"],"correct":[0],"explanation":"The pituitary gland secretes hormones such as TSH, ACTH, and FSH/LH that direct other glands, earning it the 'master gland' title (though it is itself controlled by the hypothalamus). The thyroid, adrenal, and pineal glands are targets or independent glands rather than master regulators."},
  {"section":"SCIENCE","topic":"anatomy-physiology","subtopic":"Endocrine System","difficulty":2,"stem":"Which hormone, secreted by the pancreas, lowers blood glucose by promoting cellular glucose uptake?","options":["Epinephrine","Insulin","Cortisol","Glucagon"],"correct":[1],"explanation":"Insulin from the beta cells of the pancreas lowers blood glucose by stimulating cells to take up glucose. Glucagon, cortisol, and epinephrine all raise blood glucose, acting opposite to insulin."},
  {"section":"SCIENCE","topic":"anatomy-physiology","subtopic":"Endocrine System","difficulty":3,"stem":"The thyroid hormones thyroxine (T4) and triiodothyronine (T3) primarily regulate which body process?","options":["The body's metabolic rate","Blood glucose storage as glycogen","Blood calcium levels","Blood pressure through sodium retention"],"correct":[0],"explanation":"T3 and T4 increase the basal metabolic rate, influencing energy use, heat production, and growth. Blood calcium is regulated by calcitonin and parathyroid hormone, sodium/blood pressure by aldosterone, and glycogen storage by insulin."},
  {"section":"SCIENCE","topic":"anatomy-physiology","subtopic":"Genitourinary System","difficulty":2,"stem":"What is the functional unit of the kidney responsible for filtering blood and forming urine?","options":["Alveolus","Ureter","Nephron","Glomerulus"],"correct":[2],"explanation":"The nephron is the kidney's functional unit that filters blood, reabsorbs needed substances, and produces urine. The glomerulus is only the filtering capillary tuft within a nephron, the ureter transports urine to the bladder, and the alveolus belongs to the lungs."},
  {"section":"SCIENCE","topic":"anatomy-physiology","subtopic":"Genitourinary System","difficulty":2,"stem":"Which sequence correctly describes the path of urine after it is formed in the kidney?","options":["Kidney, ureter, bladder, urethra","Kidney, ureter, urethra, bladder","Kidney, bladder, ureter, urethra","Kidney, urethra, bladder, ureter"],"correct":[0],"explanation":"Urine flows from the kidney through the ureter to the bladder for storage, then exits the body via the urethra. The other sequences misorder the ureter and urethra, which serve different roles."},
  {"section":"SCIENCE","topic":"anatomy-physiology","subtopic":"Immune System","difficulty":2,"stem":"Which type of white blood cell produces antibodies as part of the adaptive immune response?","options":["Neutrophils","Red blood cells","B lymphocytes (B cells)","Platelets"],"correct":[2],"explanation":"B lymphocytes differentiate into plasma cells that produce antibodies targeting specific antigens. Red blood cells carry oxygen, platelets aid clotting, and neutrophils are phagocytes of the innate immune system that do not make antibodies."},
  {"section":"SCIENCE","topic":"anatomy-physiology","subtopic":"Immune System","difficulty":1,"stem":"Which of the following is a part of the body's innate (nonspecific) first line of defense against pathogens?","options":["Intact skin acting as a physical barrier","Antibody production by plasma cells","B cell activation against a specific antigen","Memory T cells from a prior infection"],"correct":[0],"explanation":"Intact skin is a physical barrier and part of innate, nonspecific immunity that blocks pathogens regardless of type. Antibody production, memory T cells, and antigen-specific B cell activation are all features of adaptive (specific) immunity."},
  {"section":"SCIENCE","topic":"anatomy-physiology","subtopic":"Skeletal System","difficulty":2,"stem":"In adults, blood cells are produced primarily in which tissue?","options":["Articular cartilage","Yellow bone marrow","Compact bone matrix","Red bone marrow"],"correct":[3],"explanation":"Red bone marrow is the site of hematopoiesis, producing red and white blood cells and platelets. Yellow marrow mainly stores fat, compact bone provides structural support, and articular cartilage cushions joints."},
  {"section":"SCIENCE","topic":"anatomy-physiology","subtopic":"Skeletal System","difficulty":1,"stem":"Which of the following bones is part of the axial skeleton?","options":["Vertebral column","Humerus","Femur","Tibia"],"correct":[0],"explanation":"The axial skeleton includes the skull, vertebral column, and rib cage, forming the body's central axis. The femur, humerus, and tibia are limb bones belonging to the appendicular skeleton."},
  {"section":"SCIENCE","topic":"biology","subtopic":"Describe Cell Structure, Function, and Organization","difficulty":1,"stem":"Which organelle is the primary site of ATP production in eukaryotic cells?","options":["Lysosome","Golgi apparatus","Ribosome","Mitochondrion"],"correct":[3],"explanation":"The mitochondrion carries out cellular respiration and generates most of the cell's ATP. Ribosomes build proteins, the Golgi modifies and packages them, and lysosomes digest waste."},
  {"section":"SCIENCE","topic":"biology","subtopic":"Describe Cell Structure, Function, and Organization","difficulty":2,"stem":"A student observes a cell that has a rigid cell wall, a large central vacuole, and chloroplasts. This cell is most likely from which type of organism?","options":["A bacterium without organelles","A virus","A plant","An animal"],"correct":[2],"explanation":"Chloroplasts, a large central vacuole, and a cellulose cell wall are characteristic of plant cells. Animal cells lack cell walls and chloroplasts, and viruses are not cells."},
  {"section":"SCIENCE","topic":"biology","subtopic":"Describe Cell Structure, Function, and Organization","difficulty":2,"stem":"Which structure controls the passage of materials into and out of the cell while separating the cytoplasm from the external environment?","options":["Cell (plasma) membrane","Cytoskeleton","Endoplasmic reticulum","Nucleolus"],"correct":[0],"explanation":"The plasma membrane is selectively permeable and regulates what enters and leaves the cell. The nucleolus makes ribosome components, the ER transports materials internally, and the cytoskeleton provides shape and support."},
  {"section":"SCIENCE","topic":"biology","subtopic":"Describe Cell Structure, Function, and Organization","difficulty":3,"stem":"Rough endoplasmic reticulum is distinguished from smooth endoplasmic reticulum primarily by the presence of which feature, which gives it its function?","options":["Attached ribosomes that synthesize proteins","Digestive enzymes that break down lipids","Chlorophyll that captures light energy","Cilia that move the organelle through the cytoplasm"],"correct":[0],"explanation":"Rough ER is studded with ribosomes and is therefore involved in protein synthesis and processing, whereas smooth ER lacks ribosomes and functions mainly in lipid synthesis and detoxification."},
  {"section":"SCIENCE","topic":"biology","subtopic":"Describe the Relationship Between Genetic Material and Protein Structure","difficulty":1,"stem":"During transcription, the genetic information in DNA is used to produce which molecule?","options":["A new DNA strand identical to the original","Messenger RNA (mRNA)","A phospholipid","A protein"],"correct":[1],"explanation":"Transcription copies a DNA sequence into messenger RNA. Producing protein from mRNA is translation, and copying DNA into new DNA is replication."},
  {"section":"SCIENCE","topic":"biology","subtopic":"Describe the Relationship Between Genetic Material and Protein Structure","difficulty":2,"stem":"A segment of DNA template has the base sequence TAC. What is the corresponding mRNA codon transcribed from this template?","options":["ATG","UAC","TAC","AUG"],"correct":[3],"explanation":"RNA pairs A-U and G-C, so the template TAC is transcribed into AUG (T pairs with A, A pairs with U, C pairs with G). RNA uses uracil (U) instead of thymine (T)."},
  {"section":"SCIENCE","topic":"biology","subtopic":"Describe the Relationship Between Genetic Material and Protein Structure","difficulty":2,"stem":"Which best describes the correct flow of genetic information during gene expression?","options":["DNA is translated into RNA, which is transcribed into protein","RNA is transcribed into DNA, which is translated into protein","Protein is transcribed into RNA, which is translated into DNA","DNA is transcribed into RNA, which is translated into protein"],"correct":[3],"explanation":"The central dogma states that DNA is transcribed into RNA and RNA is translated into protein. Transcription makes RNA from DNA; translation makes protein from RNA."},
  {"section":"SCIENCE","topic":"biology","subtopic":"Describe the Relationship Between Genetic Material and Protein Structure","difficulty":3,"stem":"Translation of mRNA into a polypeptide takes place at which cellular structure, where amino acids are joined in the order specified by codons?","options":["The mitochondrial matrix only","The ribosome","The cell membrane","The nucleus"],"correct":[1],"explanation":"Ribosomes read mRNA codons and link the corresponding amino acids into a polypeptide chain. Transcription occurs in the nucleus, but translation occurs at ribosomes in the cytoplasm or on the rough ER."},
  {"section":"SCIENCE","topic":"biology","subtopic":"Describe the Relationship Between Genetic Material and Protein Structure","difficulty":3,"stem":"A point mutation changes a single DNA base, which alters one codon so that a different amino acid is inserted into a protein. This illustrates that the sequence of DNA bases ultimately determines which property of a protein?","options":["The number of mitochondria in the cell","Its location in the nucleus","The thickness of the cell wall","Its amino acid sequence and resulting structure"],"correct":[3],"explanation":"DNA base sequence specifies the order of amino acids in a protein, which in turn determines the protein's folding and function. A change in one base can change an amino acid and alter the protein."},
  {"section":"SCIENCE","topic":"biology","subtopic":"Apply Concepts Underlying Mendel's Laws of Inheritance","difficulty":1,"stem":"In pea plants, the allele for tall (T) is dominant over the allele for short (t). What is the phenotype of a plant with the genotype Tt?","options":["Medium height, blending tall and short","Tall","Short","It cannot be determined from the genotype"],"correct":[1],"explanation":"Because T (tall) is dominant, a heterozygous Tt plant shows the dominant tall phenotype. The recessive short trait appears only in tt individuals."},
  {"section":"SCIENCE","topic":"biology","subtopic":"Apply Concepts Underlying Mendel's Laws of Inheritance","difficulty":2,"stem":"In rabbits, brown fur (B) is dominant over white fur (b). Two heterozygous brown rabbits are crossed (Bb x Bb). What fraction of the offspring are expected to have white fur?","options":["0","1/2","1/4","3/4"],"correct":[2],"explanation":"A Bb x Bb cross yields a 1 BB : 2 Bb : 1 bb genotype ratio. Only bb (1 out of 4, or 1/4) shows the recessive white phenotype."},
  {"section":"SCIENCE","topic":"biology","subtopic":"Apply Concepts Underlying Mendel's Laws of Inheritance","difficulty":2,"stem":"In a certain plant, purple flowers (P) are dominant over white flowers (p). A homozygous purple plant (PP) is crossed with a white plant (pp). What percentage of the offspring are expected to have purple flowers?","options":["25%","50%","100%","75%"],"correct":[2],"explanation":"PP x pp produces all Pp offspring. Because every offspring carries the dominant P allele, 100% display purple flowers."},
  {"section":"SCIENCE","topic":"biology","subtopic":"Apply Concepts Underlying Mendel's Laws of Inheritance","difficulty":3,"stem":"In guinea pigs, black coat (B) is dominant over brown (b). A heterozygous black guinea pig is crossed with a brown guinea pig (Bb x bb). What fraction of the offspring are expected to be brown?","options":["3/4","0","1/4","1/2"],"correct":[3],"explanation":"A Bb x bb cross gives 1 Bb : 1 bb, a 1:1 ratio. The bb offspring (1/2) are brown and the Bb offspring (1/2) are black."},
  {"section":"SCIENCE","topic":"biology","subtopic":"Apply Concepts Underlying Mendel's Laws of Inheritance","difficulty":2,"stem":"Mendel's law of segregation states that during gamete formation, the two alleles for a trait separate so that each gamete carries which of the following?","options":["No alleles for the trait","One allele for the trait","A random number of alleles","Both alleles for the trait"],"correct":[1],"explanation":"By the law of segregation, paired alleles separate during meiosis, and each gamete receives only one allele for each gene. The pair is restored at fertilization."},
  {"section":"SCIENCE","topic":"biology","subtopic":"Describe the Structure and Function of the Basic Macromolecules in a Biological System","difficulty":1,"stem":"Which type of macromolecule is built from monomers called amino acids?","options":["Lipids","Nucleic acids","Proteins","Carbohydrates"],"correct":[2],"explanation":"Proteins are polymers of amino acids linked by peptide bonds. Carbohydrates are made of monosaccharides, and nucleic acids are made of nucleotides."},
  {"section":"SCIENCE","topic":"biology","subtopic":"Describe the Structure and Function of the Basic Macromolecules in a Biological System","difficulty":2,"stem":"Which macromolecule serves as the primary, quick source of energy for cells and includes monomers such as glucose?","options":["Carbohydrates","Nucleic acids","Proteins","Lipids"],"correct":[0],"explanation":"Carbohydrates, whose monomers are monosaccharides like glucose, provide a readily available energy source for cells. Lipids store energy long-term, while proteins and nucleic acids have structural and informational roles."},
  {"section":"SCIENCE","topic":"biology","subtopic":"Describe the Structure and Function of the Basic Macromolecules in a Biological System","difficulty":2,"type":"MULTI","stem":"Which of the following are functions or features of lipids in biological systems? Select all that apply.","options":["They store energy for long-term use","Their monomers are nucleotides","They are generally insoluble in water","They form the bilayer of cell membranes"],"correct":[0,2,3],"explanation":"Lipids form membrane bilayers, store energy long-term, and are hydrophobic (insoluble in water). Nucleotides are the monomers of nucleic acids, not lipids."},
  {"section":"SCIENCE","topic":"biology","subtopic":"Describe the Role of Microorganisms in Disease","difficulty":1,"stem":"Which type of pathogen causes the common cold and influenza and requires a host cell to reproduce?","options":["Fungi","Viruses","Bacteria","Protozoa"],"correct":[1],"explanation":"Colds and influenza are caused by viruses, which are not cells and can only replicate inside a living host cell. Bacteria, fungi, and protozoa can reproduce on their own."},
  {"section":"SCIENCE","topic":"biology","subtopic":"Describe the Role of Microorganisms in Disease","difficulty":2,"stem":"A patient has a bacterial infection. Which type of medication is most appropriate to treat the infection?","options":["A vaccine given after the infection to cure it","An antiviral","An antibiotic","An antihistamine"],"correct":[2],"explanation":"Antibiotics target bacteria and are used to treat bacterial infections. Antivirals act on viruses, antihistamines treat allergy symptoms, and vaccines are used to prevent rather than cure an active infection."},
  {"section":"SCIENCE","topic":"biology","subtopic":"Describe the Role of Microorganisms in Disease","difficulty":3,"stem":"Athlete's foot and ringworm are infections caused by which group of microorganisms?","options":["Helminths (worms)","Viruses","Fungi","Bacteria"],"correct":[2],"explanation":"Athlete's foot and ringworm are caused by fungi (dermatophytes) that grow on the skin. They are treated with antifungal medications rather than antibiotics or antivirals."},
  {"section":"SCIENCE","topic":"chemistry","subtopic":"Recognize Basic Atomic Structure","difficulty":1,"stem":"Which subatomic particle carries a negative electrical charge?","options":["Neutron","Electron","Nucleus","Proton"],"correct":[1],"explanation":"Electrons carry a negative charge. Protons are positive, neutrons are neutral, and the nucleus is the central region (not a particle)."},
  {"section":"SCIENCE","topic":"chemistry","subtopic":"Recognize Basic Atomic Structure","difficulty":2,"stem":"The atomic number of an element is determined by the number of which particle in its atoms?","options":["Protons plus neutrons","Protons","Electrons","Neutrons"],"correct":[1],"explanation":"The atomic number equals the number of protons in the nucleus, which defines the element. The mass number equals protons plus neutrons."},
  {"section":"SCIENCE","topic":"chemistry","subtopic":"Recognize Basic Atomic Structure","difficulty":2,"stem":"A neutral atom has a mass number of 23 and an atomic number of 11. How many neutrons does it contain?","options":["12","23","34","11"],"correct":[0],"explanation":"Neutrons = mass number minus atomic number = 23 - 11 = 12. The atomic number (11) gives the number of protons, and a neutral atom also has 11 electrons."},
  {"section":"SCIENCE","topic":"chemistry","subtopic":"Recognize Basic Atomic Structure","difficulty":3,"stem":"Two atoms are isotopes of the same element. Which statement must be true about them?","options":["They have different atomic numbers","They have different numbers of protons and the same mass number","They have the same number of neutrons but different numbers of protons","They have the same number of protons but different numbers of neutrons"],"correct":[3],"explanation":"Isotopes of an element share the same number of protons (same atomic number) but differ in their number of neutrons, giving them different mass numbers."},
  {"section":"SCIENCE","topic":"chemistry","subtopic":"Explain Physical Properties and Changes of Matter","difficulty":1,"stem":"Which of the following is a physical change rather than a chemical change?","options":["Iron rusting in moist air","Melting an ice cube into liquid water","Milk turning sour","Wood burning in a fireplace"],"correct":[1],"explanation":"Melting ice is a physical change because only the state changes; the substance remains water (H2O). Rusting, burning, and souring all form new substances, so they are chemical changes."},
  {"section":"SCIENCE","topic":"chemistry","subtopic":"Explain Physical Properties and Changes of Matter","difficulty":2,"stem":"The direct change of a substance from a solid to a gas, without passing through the liquid state, is called what?","options":["Condensation","Evaporation","Sublimation","Freezing"],"correct":[2],"explanation":"Sublimation is the phase change directly from solid to gas, as seen with dry ice (solid carbon dioxide). Condensation is gas to liquid and freezing is liquid to solid."},
  {"section":"SCIENCE","topic":"chemistry","subtopic":"Explain Physical Properties and Changes of Matter","difficulty":2,"stem":"Which of the following is a chemical property of a substance?","options":["Its boiling point","Its color","Its density","Its flammability"],"correct":[3],"explanation":"Flammability describes a substance's ability to undergo combustion, forming new substances, so it is a chemical property. Density, boiling point, and color can be observed without changing the substance's identity, making them physical properties."},
  {"section":"SCIENCE","topic":"chemistry","subtopic":"Explain Physical Properties and Changes of Matter","difficulty":3,"stem":"In which state of matter do particles have the most kinetic energy and the greatest freedom of movement?","options":["Liquid","Gas","Solid","All states have equal particle energy"],"correct":[1],"explanation":"In the gas state, particles move rapidly and independently with the highest kinetic energy and the most freedom of movement. Solid particles only vibrate in fixed positions, and liquid particles move past one another but stay close together."},
  {"section":"SCIENCE","topic":"chemistry","subtopic":"Describe Chemical Reactions","difficulty":1,"stem":"In a chemical equation, the substances written to the left of the arrow (→) are called what?","options":["Reactants","Products","Catalysts","Solvents"],"correct":[0],"explanation":"Reactants are the starting substances written on the left of the arrow, while products are the new substances formed on the right."},
  {"section":"SCIENCE","topic":"chemistry","subtopic":"Describe Chemical Reactions","difficulty":2,"stem":"The reaction 2H2 + O2 → 2H2O is best classified as which type of reaction?","options":["Double replacement","Decomposition","Single replacement","Synthesis (combination)"],"correct":[3],"explanation":"Two simpler substances (hydrogen and oxygen) combine to form a single more complex product (water), which defines a synthesis, or combination, reaction."},
  {"section":"SCIENCE","topic":"chemistry","subtopic":"Describe Chemical Reactions","difficulty":3,"stem":"What coefficient should be placed in front of O2 to correctly balance the combustion reaction CH4 + ___ O2 → CO2 + 2H2O?","options":["2","4","3","1"],"correct":[0],"explanation":"A coefficient of 2 gives 2 O2, supplying 4 oxygen atoms that match the 2 oxygen in CO2 plus the 2 oxygen in 2H2O. This balances all atoms in the combustion reaction."},
  {"section":"SCIENCE","topic":"chemistry","subtopic":"Describe Chemical Reactions","difficulty":3,"stem":"According to the law of conservation of mass, if 10 grams of reactants completely react in a sealed container, what is the total mass of the products?","options":["Exactly 10 grams","It cannot be determined","Less than 10 grams","More than 10 grams"],"correct":[0],"explanation":"The law of conservation of mass states that matter is neither created nor destroyed in a chemical reaction, so the mass of the products must equal the mass of the reactants, which is 10 grams."},
  {"section":"SCIENCE","topic":"chemistry","subtopic":"Understand Properties of Solutions","difficulty":1,"stem":"When salt is dissolved in water to make saltwater, which component is the solute?","options":["The salt","The container","The water","The saltwater mixture"],"correct":[0],"explanation":"The solute is the substance that is dissolved, which is the salt. The water is the solvent because it is present in the greater amount and does the dissolving."},
  {"section":"SCIENCE","topic":"chemistry","subtopic":"Understand Properties of Solutions","difficulty":2,"stem":"A solution has a pH of 3. This solution is best described as which of the following?","options":["Neutral","Acidic","A pure solvent","Strongly basic"],"correct":[1],"explanation":"On the pH scale of 0 to 14, values below 7 are acidic. A pH of 3 is well below 7, so the solution is acidic; a pH of 7 is neutral and above 7 is basic."},
  {"section":"SCIENCE","topic":"chemistry","subtopic":"Understand Properties of Solutions","difficulty":2,"stem":"Which change would most likely increase the rate at which a sugar cube dissolves in a glass of water?","options":["Using larger sugar crystals","Letting the glass sit undisturbed","Lowering the temperature of the water","Stirring the mixture"],"correct":[3],"explanation":"Stirring brings fresh solvent into contact with the solute and speeds dissolving. Lowering temperature, using larger crystals, or leaving it undisturbed would all slow the process."},
  {"section":"SCIENCE","topic":"chemistry","subtopic":"Understand Properties of Solutions","difficulty":3,"stem":"A solution that contains the maximum amount of dissolved solute possible at a given temperature, with no more able to dissolve, is described as what?","options":["Saturated","Colloidal","Dilute","Unsaturated"],"correct":[0],"explanation":"A saturated solution holds the maximum amount of dissolved solute at a given temperature, so additional solute will not dissolve. An unsaturated solution can still dissolve more solute."},
  {"section":"SCIENCE","topic":"scientific-reasoning","subtopic":"Use Basic Scientific Measurements and Measurement Tools","difficulty":1,"stem":"A student needs to measure the volume of a liquid sample for an experiment. Which laboratory tool is most appropriate for this measurement?","options":["Graduated cylinder","Triple-beam balance","Stopwatch","Thermometer"],"correct":[0],"explanation":"Volume of a liquid is measured with a graduated cylinder; a balance measures mass, a thermometer measures temperature, and a stopwatch measures time."},
  {"section":"SCIENCE","topic":"scientific-reasoning","subtopic":"Use Basic Scientific Measurements and Measurement Tools","difficulty":2,"stem":"A nurse reads a patient's body temperature from a digital thermometer. Which unit and value would be the most reasonable reading for a healthy adult?","options":["37 kilometers","37 milliliters","37 grams","37 degrees Celsius"],"correct":[3],"explanation":"Temperature is reported in degrees Celsius (or Fahrenheit); normal body temperature is about 37 degrees Celsius. Grams measure mass, milliliters measure volume, and kilometers measure distance."},
  {"section":"SCIENCE","topic":"scientific-reasoning","subtopic":"Use Basic Scientific Measurements and Measurement Tools","difficulty":2,"stem":"When reading the volume of water in a graduated cylinder, the surface of the water forms a curved dip called the meniscus. To read the measurement correctly, where should the student position the eye and read the scale?","options":["At eye level, reading the highest point of the curve","At eye level, reading the bottom of the meniscus","From above, reading the top edge of the water where it touches the glass","From below the cylinder, reading the lowest visible mark"],"correct":[1],"explanation":"For accurate volume measurement, the eye should be level with the liquid and the reading taken at the bottom of the meniscus to avoid parallax error."},
  {"section":"SCIENCE","topic":"scientific-reasoning","subtopic":"Use Basic Scientific Measurements and Measurement Tools","difficulty":3,"stem":"A student measures the mass of a sample three times using a balance and records 12.4 g, 12.5 g, and 12.3 g. Which statement best describes these measurements?","options":["The measurements are precise because the repeated values are close to one another","The measurements are accurate because they equal the sample's true mass","The measurements show the sample's volume in milliliters","The measurements cannot be averaged because they differ"],"correct":[0],"explanation":"Precision refers to how close repeated measurements are to each other; accuracy refers to closeness to the true value, which cannot be judged here without a known standard."},
  {"section":"SCIENCE","topic":"scientific-reasoning","subtopic":"Apply Logic and Evidence to Scientific Explanations","difficulty":1,"stem":"A scientist proposes an explanation for an observation and wants it to be considered scientific. What must the explanation be able to do?","options":["Explain every event in the universe at once","Remain unchanged regardless of new data","Be tested and potentially disproven through evidence","Be accepted by a majority vote of scientists"],"correct":[2],"explanation":"A scientific explanation must be testable and falsifiable, meaning evidence could potentially support or refute it."},
  {"section":"SCIENCE","topic":"scientific-reasoning","subtopic":"Apply Logic and Evidence to Scientific Explanations","difficulty":2,"stem":"A study reports that people who drink more coffee tend to sleep fewer hours per night. A reporter concludes that coffee directly causes people to need less sleep. Why is this conclusion logically flawed?","options":["Sleep cannot be measured in hours","A correlation between two variables does not by itself establish that one causes the other","The study did not measure coffee consumption accurately","Coffee and sleep are unrelated variables"],"correct":[1],"explanation":"The conclusion confuses correlation with causation; an observed association does not prove a direct causal link, as other factors could explain the relationship."},
  {"section":"SCIENCE","topic":"scientific-reasoning","subtopic":"Apply Logic and Evidence to Scientific Explanations","difficulty":2,"stem":"A researcher claims that a new supplement improves memory. Which piece of evidence would most strongly support this claim?","options":["A controlled study in which a treatment group taking the supplement scored higher on memory tests than a placebo group","A magazine article describing how the supplement was developed","Several customers posting online that they feel sharper after taking it","The supplement company stating it has sold millions of bottles"],"correct":[0],"explanation":"A controlled experiment comparing a treatment group to a placebo group provides the strongest evidence, while testimonials, sales figures, and descriptive articles are not controlled tests of the claim."},
  {"section":"SCIENCE","topic":"scientific-reasoning","subtopic":"Apply Logic and Evidence to Scientific Explanations","difficulty":3,"stem":"A scientist's hypothesis predicts that a certain enzyme will speed up a reaction. After many careful experiments, the data repeatedly show no change in reaction rate when the enzyme is added. What is the most appropriate response according to scientific reasoning?","options":["Conclude that enzymes never affect reaction rates","Revise or reject the hypothesis because it is not supported by the evidence","Discard the data because they conflict with the hypothesis","Keep the hypothesis unchanged because it was proposed first"],"correct":[1],"explanation":"When repeated, reliable evidence contradicts a hypothesis, the hypothesis should be revised or rejected; data are not discarded to protect an idea, and a single result cannot be generalized to all enzymes."},
  {"section":"SCIENCE","topic":"scientific-reasoning","subtopic":"Predict Relationships Among Events, Objects, and Processes","difficulty":1,"stem":"A student observes that as the temperature of a gas in a sealed, flexible container increases, the volume of the gas also increases. Based on this pattern, what should the student predict will happen if the gas is cooled?","options":["The mass of the gas will increase","The volume of the gas will decrease","The volume of the gas will increase","The gas will turn into a solid metal"],"correct":[1],"explanation":"The data show a direct relationship between temperature and volume, so cooling the gas is predicted to decrease its volume."},
  {"section":"SCIENCE","topic":"scientific-reasoning","subtopic":"Predict Relationships Among Events, Objects, and Processes","difficulty":2,"stem":"A gardener records that bean plants grow taller as the number of hours of daily sunlight increases, as shown: 2 hours -> 5 cm, 4 hours -> 9 cm, 6 hours -> 13 cm. If a plant receives 8 hours of sunlight, what height is the best prediction based on the trend?","options":["About 9 cm","About 5 cm","About 17 cm","About 13 cm"],"correct":[2],"explanation":"Height increases by about 4 cm for each additional 2 hours of sunlight, so 8 hours is predicted to give roughly 17 cm following the linear trend."},
  {"section":"SCIENCE","topic":"scientific-reasoning","subtopic":"Predict Relationships Among Events, Objects, and Processes","difficulty":2,"stem":"In a study of a predator-prey relationship, researchers find that when the population of hawks (predators) increases, the population of mice (prey) tends to decrease. Based on this inverse relationship, what is the best prediction if the hawk population suddenly declines?","options":["The mouse population will become extinct","The mouse population will tend to decrease","The mouse population will tend to increase","The hawk and mouse populations will become equal"],"correct":[2],"explanation":"With fewer predators removing mice, the prey population is predicted to rise, consistent with the inverse predator-prey relationship described."},
  {"section":"SCIENCE","topic":"scientific-reasoning","subtopic":"Predict Relationships Among Events, Objects, and Processes","difficulty":3,"stem":"A chemist measures how the rate of a reaction changes with the concentration of a reactant: 0.1 M -> 2 units/s, 0.2 M -> 4 units/s, 0.3 M -> 6 units/s. Which statement best describes the relationship and a valid prediction?","options":["Rate is unrelated to concentration, so 0.4 M cannot be predicted","Rate is directly proportional to concentration, so 0.4 M is predicted to give about 8 units/s","Rate decreases as concentration rises, so 0.4 M is predicted to give 0 units/s","Rate is inversely proportional to concentration, so 0.4 M is predicted to give about 1 unit/s"],"correct":[1],"explanation":"The rate doubles when concentration doubles and rises by 2 units/s per 0.1 M, a direct proportional relationship, so 0.4 M is predicted to give about 8 units/s."},
  {"section":"SCIENCE","topic":"scientific-reasoning","subtopic":"Apply the Scientific Method to Interpret a Scientific Investigation","difficulty":1,"stem":"A student tests whether the amount of fertilizer affects plant growth. She gives different plants different amounts of fertilizer while keeping water, light, and soil the same, and measures plant height after two weeks. What is the independent variable in this experiment?","options":["The type of soil used","The amount of fertilizer given to the plants","The amount of water given to the plants","The height of the plants after two weeks"],"correct":[1],"explanation":"The independent variable is the factor the experimenter deliberately changes; here that is the amount of fertilizer, while plant height is the dependent variable being measured."},
  {"section":"SCIENCE","topic":"scientific-reasoning","subtopic":"Apply the Scientific Method to Interpret a Scientific Investigation","difficulty":2,"stem":"A researcher tests whether a new cleaner kills more bacteria than the old cleaner. She treats identical bacterial plates with each cleaner and leaves one plate untreated. In this investigation, what is the purpose of the untreated plate?","options":["It serves as a control for comparison with the treated plates","It is the dependent variable being measured","It increases the amount of cleaner used in the test","It is the independent variable being manipulated"],"correct":[0],"explanation":"The untreated plate is the control group, providing a baseline against which the effects of the two cleaners can be compared."},
  {"section":"SCIENCE","topic":"scientific-reasoning","subtopic":"Apply the Scientific Method to Interpret a Scientific Investigation","difficulty":2,"stem":"A scientist hypothesizes that warmer water dissolves sugar faster. He stirs equal amounts of sugar into 100 mL of water at three temperatures and records the time to fully dissolve: 20 degrees C -> 90 s, 40 degrees C -> 55 s, 60 degrees C -> 30 s. Which conclusion is best supported by these data?","options":["Sugar dissolves faster in colder water","The amount of water determines dissolving time","Higher water temperature is associated with faster sugar dissolving, supporting the hypothesis","Water temperature has no effect on how fast sugar dissolves"],"correct":[2],"explanation":"As temperature rises, dissolving time falls, so the data support the hypothesis that warmer water dissolves sugar faster; the other options contradict or are not tested by the data."},
  {"section":"SCIENCE","topic":"scientific-reasoning","subtopic":"Apply the Scientific Method to Interpret a Scientific Investigation","difficulty":3,"stem":"A team tests whether a drug lowers blood pressure. They give the drug to one group and a placebo to another, but they let participants choose which group to join, and the drug group happens to contain mostly younger people. Why does this design weaken the validity of any conclusion about the drug?","options":["The dependent variable was changed instead of measured","Age is a confounding variable that was not controlled between the groups","Blood pressure cannot be measured reliably in humans","Using a placebo group makes the experiment invalid"],"correct":[1],"explanation":"Because age differs systematically between groups and was not controlled, it is a confounding variable that could explain blood pressure differences instead of the drug, undermining a valid causal conclusion."},
  {"section":"ENGLISH","topic":"conventions","subtopic":"Identifying Correct Spelling","difficulty":1,"stem":"Which word is spelled correctly?","options":["definitly","definatley","definitely","definately"],"correct":[2],"explanation":"The correct spelling is 'definitely' (from 'definite' + '-ly'). 'Definately,' 'definitly,' and 'definatley' all misspell the root or rearrange the letters."},
  {"section":"ENGLISH","topic":"conventions","subtopic":"Identifying Correct Spelling","difficulty":2,"stem":"Which word is spelled correctly?","options":["embarras","embbarrass","embarrass","embarass"],"correct":[2],"explanation":"'Embarrass' is spelled with a double 'r' and a double 's.' 'Embarass' and 'embarras' drop a letter, and 'embbarrass' incorrectly doubles the 'b.'"},
  {"section":"ENGLISH","topic":"conventions","subtopic":"Correct Use of End Punctuation","difficulty":1,"stem":"Which sentence is punctuated correctly?","options":["Which medication did the nurse administer.","Which medication did the nurse administer?","Which medication did the nurse administer!","Which medication did the nurse administer"],"correct":[1],"explanation":"\"Which medication did the nurse administer\" is a direct question, so it ends with a question mark. The period treats a question as a statement, the exclamation point adds inappropriate emphasis, and the last option omits end punctuation."},
  {"section":"ENGLISH","topic":"conventions","subtopic":"Correct Use of End Punctuation","difficulty":2,"stem":"Which sentence is punctuated correctly?","options":["She asked if I wanted dessert?","She asked if I wanted dessert.","She asked, if I wanted dessert.","She asked if I wanted dessert!"],"correct":[1],"explanation":"This is an indirect question (a reported statement), so it ends with a period, not a question mark or exclamation point. The fourth option adds an unnecessary comma after 'asked.'"},
  {"section":"ENGLISH","topic":"conventions","subtopic":"Using Commas with Introductory Words","difficulty":1,"stem":"Which sentence is punctuated correctly?","options":["However, we decided to leave early.","However we decided to leave early.","However we, decided to leave early.","However, we decided, to leave early."],"correct":[0],"explanation":"An introductory transitional word such as 'However' is followed by a comma. The second option omits that comma, while the others insert commas in incorrect places within the sentence."},
  {"section":"ENGLISH","topic":"conventions","subtopic":"Using Commas with Introductory Words","difficulty":2,"stem":"Which sentence is punctuated correctly?","options":["After the long meeting ended, we went to lunch.","After the long meeting ended we went to lunch.","After the long meeting, ended we went to lunch.","After, the long meeting ended we went to lunch."],"correct":[0],"explanation":"An introductory dependent clause is set off with a comma after it ('After the long meeting ended,'). The second option omits the comma, and the others place commas inside the clause where they break up the meaning."},
  {"section":"ENGLISH","topic":"conventions","subtopic":"Using Commas to Join Clauses Together","difficulty":2,"stem":"Which sentence is punctuated correctly?","options":["I wanted to go for a run, but it started to rain.","I wanted to go for a run but it started to rain.","I wanted to go for a run but, it started to rain.","I wanted to go for a run, it started to rain."],"correct":[0],"explanation":"Two independent clauses joined by the coordinating conjunction 'but' take a comma before the conjunction. The second option omits that comma, the third is a comma splice (no conjunction), and the fourth misplaces the comma after 'but.'"},
  {"section":"ENGLISH","topic":"conventions","subtopic":"Using Commas to Join Clauses Together","difficulty":3,"stem":"Which sentence correctly joins the two independent clauses?","options":["The museum was crowded, so we returned the next morning.","The museum was crowded; so we returned the next morning.","The museum was crowded so we returned the next morning.","The museum was crowded, we returned the next morning."],"correct":[0],"explanation":"A comma plus the coordinating conjunction 'so' correctly joins two independent clauses. The second option is a comma splice, the third omits the required comma, and the fourth wrongly uses a semicolon before a coordinating conjunction."},
  {"section":"ENGLISH","topic":"conventions","subtopic":"Using Commas with Nonessential Clauses","difficulty":2,"stem":"Which sentence is punctuated correctly?","options":["My oldest brother, who lives in Denver, is visiting next week.","My oldest brother who lives in Denver, is visiting next week.","My oldest brother who lives in Denver is visiting next week.","My oldest brother, who lives in Denver is visiting next week."],"correct":[0],"explanation":"The clause 'who lives in Denver' is nonessential (the brother is already identified as the oldest), so it is set off by a pair of commas. The other options omit one or both of the surrounding commas."},
  {"section":"ENGLISH","topic":"conventions","subtopic":"Using Commas with Nonessential Clauses","difficulty":3,"stem":"Which sentence is punctuated correctly?","options":["The novel that won the award is on display.","The novel, that won the award, is on display.","The novel, that won the award is on display.","The novel that won the award, is on display."],"correct":[0],"explanation":"'That won the award' is an essential (restrictive) clause that identifies which novel, so it takes no commas. The other options wrongly insert commas around or after an essential clause."},
  {"section":"ENGLISH","topic":"conventions","subtopic":"Commas Separating Adjectives","difficulty":2,"stem":"Which sentence is punctuated correctly?","options":["It was a bright, cheerful room.","It was a bright cheerful room.","It was a, bright cheerful room.","It was a bright, cheerful, room."],"correct":[0],"explanation":"'Bright' and 'cheerful' are coordinate adjectives (they could be reversed or joined by 'and'), so a comma separates them. The second option omits it, the third wrongly places a comma before the noun, and the fourth misplaces the comma after 'a.'"},
  {"section":"ENGLISH","topic":"conventions","subtopic":"Commas Separating Adjectives","difficulty":3,"stem":"Which sentence is punctuated correctly?","options":["He bought three old wooden chairs.","He bought three, old, wooden chairs.","He bought three, old wooden chairs.","He bought three old, wooden chairs."],"correct":[0],"explanation":"'Three old wooden' are cumulative adjectives that build on one another; they cannot be reversed or joined by 'and,' so no commas are used. The other options incorrectly insert commas between cumulative adjectives."},
  {"section":"ENGLISH","topic":"conventions","subtopic":"Using Commas in a Series","difficulty":1,"stem":"Which sentence is punctuated correctly?","options":["We bought apples, oranges, and bananas.","We bought apples oranges and bananas.","We bought apples, oranges, and, bananas.","We bought apples, oranges and, bananas."],"correct":[0],"explanation":"Items in a series are separated by commas. The second option omits the commas, the third misplaces a comma after 'and,' and the fourth adds an extra comma after 'and.'"},
  {"section":"ENGLISH","topic":"conventions","subtopic":"Using Commas in a Series","difficulty":2,"stem":"Which sentence is punctuated correctly?","options":["Before the trip, we packed our bags, checked the weather, and filled the tank.","Before the trip, we packed our bags checked the weather and filled the tank.","Before the trip, we packed our bags, checked, the weather, and filled the tank.","Before the trip, we packed our bags, checked the weather and, filled the tank."],"correct":[0],"explanation":"The three actions form a series and are separated by commas, with a comma before 'and.' The second option omits the series commas, the third misplaces a comma after 'and,' and the fourth adds an extra comma after 'checked.'"},
  {"section":"ENGLISH","topic":"conventions","subtopic":"Correctly Punctuating Quotations","difficulty":2,"stem":"Which sentence is punctuated correctly?","options":["She said, \"I will meet you at noon.\"","She said \"I will meet you at noon.\"","She said, \"I will meet you at noon,\"","She said, \"I will meet you at noon\"."],"correct":[0],"explanation":"A comma follows the speaker tag before the quotation, and the closing period goes inside the quotation marks. The second option omits the comma, the third places the period outside the quotation marks, and the fourth ends with a comma, leaving the sentence incomplete."},
  {"section":"ENGLISH","topic":"conventions","subtopic":"Correctly Punctuating Quotations","difficulty":3,"stem":"Which sentence is punctuated correctly?","options":["\"Let's leave early,\" he suggested.","\"Let's leave early.\" he suggested.","\"Let's leave early,\" He suggested.","\"Let's leave early\", he suggested."],"correct":[0],"explanation":"When a quotation is followed by a speaker tag, it ends with a comma inside the quotation marks, and the tag begins with a lowercase letter. The second option uses a period before the tag, the third puts the comma outside the marks, and the fourth wrongly capitalizes 'He.'"},
  {"section":"ENGLISH","topic":"conventions","subtopic":"Correct Use of Colons","difficulty":2,"stem":"Which sentence uses a colon correctly?","options":["We need three things; bread, milk, and eggs.","We need: bread, milk, and eggs.","We need three things: bread, milk, and eggs.","We need three things, bread, milk, and eggs."],"correct":[2],"explanation":"A colon follows a complete independent clause to introduce a list. The second option places a colon right after the verb (an incomplete clause), the third wrongly uses a semicolon, and the fourth uses a comma where a colon is needed."},
  {"section":"ENGLISH","topic":"conventions","subtopic":"Correct Use of Colons","difficulty":3,"stem":"Which sentence uses a colon correctly?","options":["My favorite season is: autumn.","My favorite season is obvious; autumn.","My favorite season is obvious: autumn.","My favorite season is obvious, autumn."],"correct":[2],"explanation":"A colon follows the complete clause 'My favorite season is obvious' to introduce the answer. The second option misuses a semicolon (autumn is not an independent clause), the third places the colon after a linking verb in an incomplete clause, and the fourth uses a weak comma."},
  {"section":"ENGLISH","topic":"conventions","subtopic":"Correct Use of Parentheses","difficulty":2,"stem":"Which sentence uses parentheses correctly?","options":["The museum (founded in 1925), reopened last spring.","The museum (founded in 1925 reopened last spring).","The museum founded in 1925) reopened last spring.","The museum (founded in 1925) reopened last spring."],"correct":[3],"explanation":"Parentheses enclose the nonessential information 'founded in 1925' as a matched pair within the sentence. The second option lacks an opening parenthesis, the third encloses the wrong words, and the fourth adds an unnecessary comma after the closing parenthesis."},
  {"section":"ENGLISH","topic":"conventions","subtopic":"Correct Use of Parentheses","difficulty":3,"stem":"Which sentence uses parentheses correctly?","options":["We finally reached the summit (after six hours)","We finally reached the summit. (after six hours)","We finally reached the summit (after six hours.)","We finally reached the summit (after six hours)."],"correct":[3],"explanation":"When a parenthetical phrase ends a sentence, the closing period goes outside the closing parenthesis. The second option puts the period inside, the third wrongly ends the sentence before the parentheses, and the fourth omits end punctuation."},
  {"section":"ENGLISH","topic":"conventions","subtopic":"Types of Sentences","difficulty":2,"stem":"Which sentence is a compound sentence?","options":["When the rain stopped, the sun came out.","The rain stopped, and the sun came out.","The rain stopped and dried the streets.","After a long storm."],"correct":[1],"explanation":"A compound sentence joins two independent clauses with a comma and coordinating conjunction ('and'). The second option is complex (it has a dependent clause), the third is a simple sentence with a compound predicate, and the fourth is a fragment."},
  {"section":"ENGLISH","topic":"conventions","subtopic":"Types of Sentences","difficulty":2,"stem":"Which sentence is imperative?","options":["The window is open.","What a cold draft that is!","Did you close the window?","Please close the window before you leave."],"correct":[3],"explanation":"An imperative sentence gives a command or request, with an understood subject 'you.' The second option is interrogative (a question), the third is declarative (a statement), and the fourth is exclamatory."},
  {"section":"ENGLISH","topic":"conventions","subtopic":"Identifying Correct Sentence Structure","difficulty":2,"stem":"Which sentence is structured correctly, with no run-on or fragment?","options":["Because the train was late.","The train was late we missed our connection.","The train was late, we missed our connection.","The train was late, so we missed our connection."],"correct":[3],"explanation":"This option correctly joins two independent clauses with a comma and coordinating conjunction. The second option is a run-on (fused sentence), the third is a fragment, and the fourth is a comma splice."},
  {"section":"ENGLISH","topic":"conventions","subtopic":"Identifying Correct Sentence Structure","difficulty":3,"stem":"Which of the following is a complete sentence?","options":["Because the committee could not reach an agreement.","Announcing its decision after a long debate.","The committee will announce its decision tomorrow.","The committee, which met for several hours yesterday afternoon."],"correct":[2],"explanation":"A complete sentence needs a subject and a main verb expressing a complete thought ('committee will announce'). The second option lacks a main verb for its subject, the third is a participial phrase, and the fourth is a dependent clause fragment."},
  {"section":"ENGLISH","topic":"conventions","subtopic":"Subject-Verb Agreement","difficulty":2,"stem":"Which sentence has correct subject-verb agreement?","options":["The box of chocolates were a gift.","The boxes of chocolate was on the table.","The box of chocolates are a gift.","The box of chocolates was a gift."],"correct":[3],"explanation":"The subject is the singular 'box,' so it takes the singular verb 'was'; the phrase 'of chocolates' does not change the subject. The other options pair a singular subject with a plural verb or a plural subject with a singular verb."},
  {"section":"ENGLISH","topic":"conventions","subtopic":"Subject-Verb Agreement","difficulty":3,"stem":"Which sentence has correct subject-verb agreement?","options":["Each of the students have a locker.","Neither of the answers are correct.","The list of names were posted.","Each of the students has a locker."],"correct":[3],"explanation":"The indefinite pronoun 'Each' is singular and takes 'has.' 'Each' and 'Neither' are singular, so 'have' and 'are' disagree, and 'list' is singular, so 'were' disagrees in the final option."},
  {"section":"ENGLISH","topic":"conventions","subtopic":"Misplaced and Dangling Modifiers","difficulty":2,"stem":"Which sentence is written correctly, with no dangling or misplaced modifier?","options":["Walking to school the wallet was lying on the sidewalk.","Walking to school, the sidewalk had a wallet on it.","Walking to school, I found a wallet on the sidewalk.","Walking to school, a wallet was found on the sidewalk."],"correct":[2],"explanation":"The introductory modifier 'Walking to school' must describe the subject that follows; here 'I' was walking. In the other options the modifier dangles, illogically attaching to 'a wallet' or 'the sidewalk' (and the last also omits the comma)."},
  {"section":"ENGLISH","topic":"conventions","subtopic":"Misplaced and Dangling Modifiers","difficulty":3,"stem":"Which sentence places the modifier correctly?","options":["The girl waved at the passing bus that was wearing a bright red coat.","Wearing a bright red coat, the passing bus was waved at by the girl.","Wearing a bright red coat, the girl waved at the passing bus.","The girl waved at the passing bus wearing a bright red coat."],"correct":[2],"explanation":"The modifier 'Wearing a bright red coat' should sit next to the noun it describes, 'the girl.' In the other options the phrase is misplaced or dangling, making it sound as though the bus is wearing the coat."},
  {"section":"ENGLISH","topic":"knowledge-language","subtopic":"Identifying Genre","difficulty":1,"stem":"Read the following passage: \"Maria crept down the creaking staircase, her heart pounding. A shadow moved across the moonlit hall, and she gasped as the floorboard groaned beneath her bare foot.\" Which genre does this passage best represent?","options":["Persuasive essay","News report","Technical writing","Narrative fiction"],"correct":[3],"explanation":"The passage tells a story with a named character, vivid description, and rising suspense, which are hallmarks of narrative fiction."},
  {"section":"ENGLISH","topic":"knowledge-language","subtopic":"Identifying Genre","difficulty":2,"stem":"Read the following passage: \"Step 1: Unplug the device. Step 2: Remove the four screws on the back panel. Step 3: Gently lift the cover and locate the battery.\" Which genre does this passage best represent?","options":["Poetry","Technical/instructional writing","Editorial","Personal memoir"],"correct":[1],"explanation":"Numbered, sequential directions that tell the reader how to complete a task identify this as technical or instructional writing."},
  {"section":"ENGLISH","topic":"knowledge-language","subtopic":"Identifying Genre","difficulty":2,"stem":"Read the following passage: \"The city council should fund the new bike lanes immediately. Safer streets reduce accidents, and residents deserve healthier commuting options now.\" Which genre does this passage best represent?","options":["Biography","Expository report","Persuasive writing","Fictional narrative"],"correct":[2],"explanation":"The writer takes a clear position and urges action using reasons, which marks the passage as persuasive writing."},
  {"section":"ENGLISH","topic":"knowledge-language","subtopic":"Matching Sentences to Types of Writing","difficulty":1,"stem":"Which sentence is an example of descriptive writing?","options":["You must register before Friday to reserve your seat.","In 1969, astronauts first landed on the Moon.","First, gather two eggs, a cup of flour, and a pinch of salt.","The velvety red petals curled toward the warm afternoon sun."],"correct":[3],"explanation":"Descriptive writing uses sensory detail to paint a picture; \"velvety red petals\" appealing to sight and touch is descriptive."},
  {"section":"ENGLISH","topic":"knowledge-language","subtopic":"Matching Sentences to Types of Writing","difficulty":2,"stem":"Which sentence is an example of expository writing?","options":["Vote yes on Proposition 4 to protect our parks.","The dragon's scales shimmered like emeralds in the torchlight.","Please, oh please, let the rain hold off until the picnic ends!","Photosynthesis is the process by which plants convert sunlight into chemical energy."],"correct":[3],"explanation":"Expository writing explains or informs without opinion; defining photosynthesis simply conveys factual information."},
  {"section":"ENGLISH","topic":"knowledge-language","subtopic":"Matching Sentences to Types of Writing","difficulty":3,"stem":"Which sentence is an example of narrative writing?","options":["The mitochondria are the powerhouse of the cell.","Combine the dry ingredients before adding the milk.","As the train pulled away, Daniel realized he had left his ticket on the bench.","Recycling reduces landfill waste and conserves natural resources."],"correct":[2],"explanation":"Narrative writing recounts an event or story involving a character; Daniel's experience as the train departs tells a story."},
  {"section":"ENGLISH","topic":"knowledge-language","subtopic":"Identifying Intended Audience","difficulty":2,"stem":"Read the following passage: \"Remember to bring your permission slip and a sack lunch for tomorrow's field trip. The bus leaves the school at 8:00 a.m. sharp, so be on time!\" Who is the most likely intended audience?","options":["University researchers","Government legislators","Medical professionals","Students and their parents"],"correct":[3],"explanation":"References to permission slips, a sack lunch, and a school field trip signal that the message addresses students and parents."},
  {"section":"ENGLISH","topic":"knowledge-language","subtopic":"Identifying Intended Audience","difficulty":3,"stem":"Read the following passage: \"Administer 250 mg orally every eight hours, and monitor the patient for hepatic enzyme elevation throughout the treatment course.\" Who is the most likely intended audience?","options":["Elementary school children","Healthcare providers","Travel enthusiasts","General newspaper readers"],"correct":[1],"explanation":"The clinical dosing instructions and technical terms like \"hepatic enzyme elevation\" indicate the audience is healthcare providers."},
  {"section":"ENGLISH","topic":"knowledge-language","subtopic":"Identifying Appropriate Language for Intended Audience/Tone","difficulty":1,"stem":"A nurse is writing a brochure to explain a procedure to first-time patients. Which sentence uses the most appropriate language for this audience?","options":["The clinician will perform a percutaneous transluminal intervention on the affected vasculature.","The vessel's occlusion necessitates an endovascular recanalization.","The doctor will use a thin tube to open the blocked blood vessel.","We'll snake a catheter through your vasculature to address the stenosis."],"correct":[2],"explanation":"For first-time patients, plain, clear language without jargon is most appropriate; \"a thin tube to open the blocked blood vessel\" is accessible."},
  {"section":"ENGLISH","topic":"knowledge-language","subtopic":"Identifying Appropriate Language for Intended Audience/Tone","difficulty":2,"stem":"A student is writing a formal cover letter to apply for a job. Which sentence has the most appropriate tone?","options":["Hey, I'd be super pumped to work for you guys!","I really, really want this job, so please pick me.","You won't regret hiring me, trust me on that.","I am writing to express my strong interest in the advertised position."],"correct":[3],"explanation":"A formal cover letter calls for a professional, respectful tone; \"I am writing to express my strong interest\" meets that standard."},
  {"section":"ENGLISH","topic":"knowledge-language","subtopic":"Identifying Appropriate Language for Intended Audience/Tone","difficulty":3,"stem":"A writer wants to create a warm, encouraging tone in a note to a friend who is nervous about an exam. Which sentence best achieves this tone?","options":["Statistically, most students pass on their first attempt.","You've studied so hard, and I know you're going to do great tomorrow.","Just don't mess this up like you did last time.","Failure to prepare adequately will result in an unsatisfactory outcome."],"correct":[1],"explanation":"A warm, encouraging tone uses supportive, positive language; \"You've studied so hard, and I know you're going to do great\" reassures the friend."},
  {"section":"ENGLISH","topic":"knowledge-language","subtopic":"Stages of the Writing Process","difficulty":1,"type":"ORDERED","stem":"Arrange the stages of the writing process in their correct order, from first to last.","options":["Revising","Prewriting","Publishing","Drafting","Editing"],"correct":[1,3,0,4,2],"explanation":"The writing process moves from generating ideas (prewriting) to drafting, then revising content, editing mechanics, and finally publishing."},
  {"section":"ENGLISH","topic":"knowledge-language","subtopic":"Stages of the Writing Process","difficulty":2,"stem":"A writer is brainstorming ideas and creating a cluster map before composing any sentences. Which stage of the writing process is the writer in?","options":["Prewriting","Editing","Drafting","Publishing"],"correct":[0],"explanation":"Brainstorming and mapping ideas before writing sentences are activities of the prewriting stage."},
  {"section":"ENGLISH","topic":"knowledge-language","subtopic":"Stages of the Writing Process","difficulty":2,"stem":"After finishing a complete draft, a writer rereads it to reorganize paragraphs and strengthen weak arguments before checking for grammar errors. Which stage of the writing process is this?","options":["Publishing","Prewriting","Revising","Proofreading for spelling only"],"correct":[2],"explanation":"Reorganizing content and strengthening ideas in a completed draft is revising, which focuses on the substance of the writing rather than mechanics."},
  {"section":"ENGLISH","topic":"knowledge-language","subtopic":"Parts of a Paragraph","difficulty":2,"stem":"Read the paragraph: \"(1) Regular exercise offers many benefits for mental health. (2) Physical activity releases endorphins that improve mood. (3) It also reduces stress and anxiety over time. (4) Studies link consistent workouts to better sleep quality.\" Which sentence is the topic sentence?","options":["Sentence 4","Sentence 3","Sentence 1","Sentence 2"],"correct":[2],"explanation":"The topic sentence states the paragraph's main idea; Sentence 1 introduces the overall claim that exercise benefits mental health, which the others support."},
  {"section":"ENGLISH","topic":"knowledge-language","subtopic":"Parts of a Paragraph","difficulty":2,"stem":"Read the paragraph: \"(1) The library introduced several new services this year. (2) It now offers free online tutoring for students. (3) A new makerspace provides 3D printers and craft tools. (4) Clearly, the library has expanded to better serve the community.\" Which sentence is the concluding sentence?","options":["Sentence 1","Sentence 3","Sentence 4","Sentence 2"],"correct":[2],"explanation":"A concluding sentence wraps up the paragraph; Sentence 4 uses \"Clearly\" to summarize the point that the library expanded its services."},
  {"section":"ENGLISH","topic":"knowledge-language","subtopic":"Parts of a Paragraph","difficulty":3,"stem":"Read the paragraph: \"(1) Honeybees play a crucial role in agriculture. (2) They pollinate roughly one-third of the crops people eat. (3) Without their pollination, many fruits and vegetables would become scarce. (4) Farmers often rent hives during the growing season to ensure good harvests.\" Which sentence provides a supporting detail rather than the main idea?","options":["Sentence 2 is a supporting detail","Sentence 1 is a supporting detail","None of the sentences support the main idea","Sentence 1 is the supporting detail and Sentence 2 is the topic"],"correct":[0],"explanation":"Sentence 1 is the topic sentence stating the main idea; Sentence 2 supplies a specific supporting detail (the pollination statistic) that backs up that claim."},
  {"section":"ENGLISH","topic":"knowledge-language","subtopic":"Identifying Unrelated Sentences","difficulty":2,"stem":"Read the paragraph: \"(1) Composting reduces household waste significantly. (2) Food scraps and yard clippings break down into rich soil. (3) My cousin recently adopted a golden retriever named Max. (4) Adding compost to a garden helps plants grow stronger.\" Which sentence does NOT belong?","options":["Sentence 4","Sentence 3","Sentence 1","Sentence 2"],"correct":[1],"explanation":"Sentences 1, 2, and 4 all discuss composting, while Sentence 3 about a cousin's dog is unrelated to the topic."},
  {"section":"ENGLISH","topic":"knowledge-language","subtopic":"Identifying Unrelated Sentences","difficulty":3,"stem":"Read the paragraph: \"(1) The ancient Romans were skilled engineers. (2) They built durable roads that connected their vast empire. (3) Their aqueducts carried fresh water across great distances. (4) Modern smartphones can now translate dozens of languages instantly. (5) Many Roman structures still stand today.\" Which sentence does NOT belong?","options":["Sentence 4","Sentence 2","Sentence 3","Sentence 5"],"correct":[0],"explanation":"The paragraph focuses on Roman engineering achievements; Sentence 4 about modern smartphones is off-topic and unrelated."},
  {"section":"ENGLISH","topic":"knowledge-language","subtopic":"Using Grammar to Enhance Clarity in Writing","difficulty":2,"stem":"Which revision of the sentence is the clearest and most concise without changing the meaning? Original: \"Due to the fact that it was raining heavily, we made the decision to cancel the outdoor event.\"","options":["Due to the fact that it was raining heavily, we made the decision to cancel the outdoor event.","We made a decision, because of the rain, to cancel the event outdoors.","On account of heavy rain occurring, a decision was made by us to cancel.","Because it was raining heavily, we decided to cancel the outdoor event."],"correct":[3],"explanation":"\"Because\" replaces the wordy \"due to the fact that\" and \"decided\" replaces \"made the decision,\" producing a concise, clear sentence with the same meaning."},
  {"section":"ENGLISH","topic":"knowledge-language","subtopic":"Using Grammar to Enhance Clarity in Writing","difficulty":3,"stem":"Which revision is the clearest and grammatically correct? Original: \"Walking to school, the backpack felt heavy on the student's shoulders.\"","options":["The backpack, walking to school, felt heavy on the student's shoulders.","As the student walked to school, the backpack felt heavy on her shoulders.","Walking to school, the backpack felt heavy on the student's shoulders.","Heavy on the shoulders, walking to school was the backpack of the student."],"correct":[1],"explanation":"The original dangles the modifier \"Walking to school\" onto the backpack; the correct revision clarifies that the student is walking, fixing the dangling modifier."},
  {"section":"ENGLISH","topic":"vocabulary","subtopic":"Using Prefixes to Determine Word Meaning","difficulty":1,"stem":"The prefix in the word \"malfunction\" most nearly means which of the following?","options":["Again or repeated","Before in time","Bad or faulty","Many"],"correct":[2],"explanation":"The prefix \"mal-\" means bad or wrong, so a malfunction is a faulty or bad operation. \"Before\" would be \"ante-\" and \"again\" would be \"re-.\""},
  {"section":"ENGLISH","topic":"vocabulary","subtopic":"Using Prefixes to Determine Word Meaning","difficulty":2,"stem":"Based on its prefix, the word \"antecedent\" refers to something that comes in what way?","options":["Before","Around","Against","After"],"correct":[0],"explanation":"The prefix \"ante-\" means before, so an antecedent is something that goes before. \"Against\" is \"anti-\" and \"around\" is \"circum-.\""},
  {"section":"ENGLISH","topic":"vocabulary","subtopic":"Using Prefixes to Determine Word Meaning","difficulty":2,"stem":"Using the prefix, what does \"circumnavigate\" most likely mean?","options":["To sail across","To sail around","To sail under","To sail against"],"correct":[1],"explanation":"The prefix \"circum-\" means around, so to circumnavigate is to travel completely around something. \"Trans-\" would mean across and \"sub-\" would mean under."},
  {"section":"ENGLISH","topic":"vocabulary","subtopic":"Using Prefixes to Determine Word Meaning","difficulty":3,"stem":"The prefix in \"benevolent\" suggests that a benevolent person is characterized by what quality?","options":["Fear of others","Ill will toward others","Good will toward others","Indifference to others"],"correct":[2],"explanation":"The prefix \"bene-\" means good or well, so a benevolent person shows good will. The opposite prefix \"mal-\" (bad) would produce \"malevolent.\""},
  {"section":"ENGLISH","topic":"vocabulary","subtopic":"Using Suffixes to Determine Word Meaning","difficulty":1,"stem":"The suffix in the word \"cardiology\" indicates that cardiology is best described as what?","options":["The study of the heart","The inflammation of the heart","The removal of the heart","The fear of the heart"],"correct":[0],"explanation":"The suffix \"-ology\" means the study of, so cardiology is the study of the heart. Fear would be \"-phobia\" and inflammation would be \"-itis.\""},
  {"section":"ENGLISH","topic":"vocabulary","subtopic":"Using Suffixes to Determine Word Meaning","difficulty":2,"stem":"Based on its suffix, a person described as \"acrophobic\" experiences what?","options":["A love of something","A study of something","A fear of something","A skill at something"],"correct":[2],"explanation":"The suffix \"-phobia\" (adjective form \"-phobic\") means an extreme fear, so an acrophobic person fears heights. The study of something would use \"-ology.\""},
  {"section":"ENGLISH","topic":"vocabulary","subtopic":"Using Suffixes to Determine Word Meaning","difficulty":2,"stem":"The suffix in the word \"breakable\" shows that something breakable is what?","options":["Without breaks","One who breaks","The act of breaking","Able to be broken"],"correct":[3],"explanation":"The suffix \"-able\" means capable of or able to be, so breakable means able to be broken. \"Without\" would be \"-less\" and \"one who\" would be \"-er.\""},
  {"section":"ENGLISH","topic":"vocabulary","subtopic":"Using Suffixes to Determine Word Meaning","difficulty":3,"stem":"Considering its suffix, the word \"courageous\" most nearly means which of the following?","options":["One who gives courage","The study of courage","Full of courage","Lacking courage"],"correct":[2],"explanation":"The suffix \"-ous\" means full of or possessing, so courageous means full of courage. \"Lacking\" would be expressed by \"-less.\""},
  {"section":"ENGLISH","topic":"vocabulary","subtopic":"Using Common Root Words to Determine Word Meaning","difficulty":1,"stem":"The root in the word \"aquatic\" most nearly means which of the following?","options":["Earth","Fire","Water","Air"],"correct":[2],"explanation":"The root \"aqua\" means water, so aquatic refers to things related to water. The root for air would be \"aero\" and for earth would be \"terra.\""},
  {"section":"ENGLISH","topic":"vocabulary","subtopic":"Using Common Root Words to Determine Word Meaning","difficulty":2,"stem":"Based on its root, the word \"chronological\" is most closely related to which concept?","options":["Time","Distance","Color","Sound"],"correct":[0],"explanation":"The root \"chrono\" means time, so chronological means arranged in order of time. The root \"chrom\" (not \"chrono\") relates to color."},
  {"section":"ENGLISH","topic":"vocabulary","subtopic":"Using Common Root Words to Determine Word Meaning","difficulty":2,"stem":"The root in the words \"dictate\" and \"dictionary\" most nearly means what?","options":["To hear","To write","To see","To speak or say"],"correct":[3],"explanation":"The root \"dict\" means to speak or say, which underlies both dictate and dictionary. The root for writing is \"scrib/script\" and for seeing is \"spect.\""},
  {"section":"ENGLISH","topic":"vocabulary","subtopic":"Using Common Root Words to Determine Word Meaning","difficulty":3,"stem":"Knowing that the root \"spect\" appears in \"spectator,\" \"inspect,\" and \"spectacle,\" you can conclude this root means what?","options":["To look or see","To carry or bring","To break or shatter","To move or run"],"correct":[0],"explanation":"The root \"spect\" means to look or see, which connects spectator, inspect, and spectacle. The root for carrying is \"port\" and for breaking is \"rupt.\""},
  {"section":"ENGLISH","topic":"vocabulary","subtopic":"Use Context Clues to Determine Word Meaning","difficulty":1,"stem":"Read the sentence below.\n\nAfter the long hike in the summer heat, the travelers were so parched that they drank an entire bottle of water in seconds.\n\nAs used in the sentence, the word \"parched\" most nearly means which of the following?","options":["Extremely thirsty","Badly injured","Pleasantly cool","Completely exhausted"],"correct":[0],"explanation":"The clue that the travelers drank an entire bottle of water immediately shows that parched means extremely thirsty or dried out, not merely tired."},
  {"section":"ENGLISH","topic":"vocabulary","subtopic":"Use Context Clues to Determine Word Meaning","difficulty":2,"stem":"Read the sentence below.\n\nUnlike his gregarious sister, who loved crowded parties and constant conversation, Marcus preferred to spend his evenings alone with a book.\n\nAs used in the sentence, the word \"gregarious\" most nearly means which of the following?","options":["Wealthy and generous","Sociable and outgoing","Quiet and withdrawn","Clever and witty"],"correct":[1],"explanation":"The contrast word \"Unlike\" signals that gregarious is the opposite of Marcus's solitary nature, so it means sociable and outgoing, fitting the sister who loves crowded parties."},
  {"section":"ENGLISH","topic":"vocabulary","subtopic":"Use Context Clues to Determine Word Meaning","difficulty":2,"stem":"Read the sentence below.\n\nThe new manager was known for being frugal, carefully tracking every expense and refusing to waste even a single dollar of the company's budget.\n\nAs used in the sentence, the word \"frugal\" most nearly means which of the following?","options":["Careful with money","Confused about money","Dishonest about money","Generous with money"],"correct":[0],"explanation":"The details of tracking every expense and refusing to waste money define frugal as economical or careful with money, the opposite of generous spending."},
  {"section":"ENGLISH","topic":"vocabulary","subtopic":"Use Context Clues to Determine Word Meaning","difficulty":3,"stem":"Read the sentence below.\n\nThe witness's testimony was so mendacious that the jury, after uncovering several deliberate lies, refused to believe a single word she said.\n\nAs used in the sentence, the word \"mendacious\" most nearly means which of the following?","options":["Untruthful or dishonest","Frightening or alarming","Lengthy or detailed","Confusing or unclear"],"correct":[0],"explanation":"The phrase \"several deliberate lies\" and the jury's refusal to believe her supply the clue that mendacious means untruthful or dishonest, not merely confusing."},
];
